//+------------------------------------------------------------------+
//|  BreakoutNY_v1_DJI30_FP.mq5                                     |
//|  BreakoutNY Strategy — DJI30 (Dow Jones) — FundingPips          |
//|  Timeframe : M5                                                  |
//|  Adapted from BreakoutNY v9.0 FINAL (NAS100)                    |
//|  Date      : March 2026                                          |
//|                                                                  |
//|  CONTRACT SPECS (DJI30 FundingPips — verified 2026-03-26):      |
//|    Symbol       : DJI30                                          |
//|    ContractSize : 5.0                                            |
//|    TickSize     : 0.01                                           |
//|    TickValue    : 0.05 USD                                       |
//|    Point        : 0.01                                           |
//|    VolumeMin    : 0.01                                           |
//|    VolumeMax    : 100.0                                          |
//|    VolumeStep   : 0.01                                           |
//|    ValuePerPoint: 5.0 USD/_Point/lot                             |
//|                                                                  |
//|  LOTSIZE NOTE:                                                   |
//|    Min risk per trade ~$300–750 due to VolumeMin=0.01           |
//|    Designed for $25,000 account (~1-3% risk per trade)          |
//+------------------------------------------------------------------+
#property copyright "BreakoutNY DJI30"
#property version   "1.00"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

CTrade         trade;
CPositionInfo  posInfo;

//--- Input Parameters
//=== HORARIO ===
input int    ServerOffsetHours  = 2;     // Server offset from UTC (UTC+2 FundingPips — verify DST)
input int    EntryWindowEnd_Min = 15;    // Entry window closes at 14:50+15 = 15:05 UTC
input int    SessionCloseHour   = 17;    // Force close hour (UTC)
input int    SessionCloseMin    = 0;     // Force close minutes (UTC)

//=== RIESGO ===
input double RiskAmountUSD      = 750.0; // Risk per trade in USD (~3% of $25k, min viable for DJI30)

//=== OBJETIVOS ===
input double TP1_RR             = 1.0;   // TP1 ratio (activates breakeven)
input double TP2_RR             = 2.0;   // TP2 ratio (SL moves to TP1)
input double TP3_RR             = 3.0;   // TP3 ratio (final target)

//=== PARCIALES ===
input bool   EnablePartials     = false; // Partial closes (validated off in NAS100)
input double TP1_ClosePct       = 40.0;  // % to close at TP1 if partials enabled
input double TP2_ClosePct       = 40.0;  // % to close at TP2 if partials enabled

//=== BREAKEVEN ===
input double BE_BufferPct       = 20.0;  // Breakeven buffer: 20% of original SL

//=== FILTROS DE DIAS ===
input bool   FilterMonday       = true;  // true = TRADE on Monday
input bool   FilterTuesday      = true;  // true = TRADE on Tuesday
input bool   FilterWednesday    = true;  // true = TRADE on Wednesday (measure first for DJI30!)
input bool   FilterThursday     = true;  // true = TRADE on Thursday
input bool   FilterFriday       = true;  // true = TRADE on Friday

//=== FILTRO RANGO ===
input double MinSL_Points       = 300.0; // Min SL in _Points (calibrate with calibrator script)
input double MaxSL_Points       = 2000.0;// Max SL in _Points (calibrate with calibrator script)
input bool   ConfirmOnClose     = true;  // ALWAYS true — confirm on candle close

//=== FILTRO ATR ===
input bool   ATR_FilterEnable   = true;  // ALWAYS true in production
input int    ATR_Period         = 14;    // ATR period
input double ATR_MaxMultiplier  = 2.0;   // Max ATR multiplier vs baseline
input double ATR_MinMultiplier  = 0.5;   // Min ATR multiplier vs baseline
input int    ATR_BaselineDays   = 20;    // Days to calculate ATR baseline

//=== LOGGING ===
input bool   EnableCSV          = true;
input string CSVFileName        = "BreakoutNY_DJI30_trades";
input int    MagicNumber        = 202402; // Different from NAS100 (202401)

//--- Global Variables
double   rangeHigh      = 0;
double   rangeLow       = 0;
double   slDistance     = 0;   // In _Points
double   cachedLots     = 0;   // Calculated once when range forms
bool     rangeFormed    = false;
bool     tradeOpenedToday = false;
bool     breakoutPending  = false;
int      breakoutDir      = 0;  // 1=BUY, -1=SELL
datetime breakoutCandleTime = 0;

// Trailing stop state
double   originalSL     = 0;
double   entryPrice     = 0;
double   beLevel        = 0;
double   tp1Level       = 0;
double   tp2Level       = 0;
double   tp3Level       = 0;
bool     beActivated    = false;
bool     tp1Hit         = false;
bool     tp2Hit         = false;

// ATR handle
int      atrHandle      = INVALID_HANDLE;

// CSV log
int      csvHandle      = INVALID_HANDLE;

// Last processed bar time
datetime lastBarTime    = 0;

//+------------------------------------------------------------------+
//| Expert initialization                                            |
//+------------------------------------------------------------------+
int OnInit()
{
   trade.SetExpertMagicNumber(MagicNumber);
   trade.SetDeviationInPoints(20);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   //--- Print contract specs for verification
   Print("=== BreakoutNY v1.0 DJI30 FundingPips ===");
   Print("Symbol        : ", _Symbol);
   Print("ContractSize  : ", SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE));
   Print("TickSize      : ", SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE));
   Print("TickValue     : ", SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE));
   Print("Point         : ", _Point);
   Print("VolumeMin     : ", SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN));
   Print("VolumeMax     : ", SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX));
   Print("VolumeStep    : ", SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP));
   double vpp = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE) /
                SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   Print("ValuePerPoint : ", vpp, " USD/_Point/lot");
   Print("RiskAmountUSD : ", RiskAmountUSD);
   Print("ServerOffset  : UTC+", ServerOffsetHours);
   Print("==========================================");

   //--- Verify we're on M5
   if(_Period != PERIOD_M5)
   {
      Print("ERROR: EA must run on M5 timeframe. Current: ", EnumToString(_Period));
      return(INIT_FAILED);
   }

   //--- ATR indicator
   atrHandle = iATR(_Symbol, PERIOD_M5, ATR_Period);
   if(atrHandle == INVALID_HANDLE)
   {
      Print("ERROR: Failed to create ATR indicator");
      return(INIT_FAILED);
   }

   //--- CSV log
   if(EnableCSV)
   {
      string path = CSVFileName + ".csv";
      csvHandle = FileOpen(path, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
      if(csvHandle != INVALID_HANDLE)
      {
         FileWrite(csvHandle,
            "Date","Day","Direction","EntryPrice","SL","TP1","TP2","TP3",
            "Lots","RiskUSD","ExitPrice","ExitReason","PnL","RangePoints",
            "ATR_Current","ATR_Baseline");
         FileFlush(csvHandle);
      }
   }

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization                                          |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if(csvHandle != INVALID_HANDLE)
   {
      FileFlush(csvHandle);
      FileClose(csvHandle);
   }
   if(atrHandle != INVALID_HANDLE)
      IndicatorRelease(atrHandle);
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   //--- Get current UTC time
   datetime serverTime = TimeCurrent();
   datetime utcTime    = serverTime - ServerOffsetHours * 3600;

   MqlDateTime utcDT;
   TimeToStruct(utcTime, utcDT);

   int utcHour = utcDT.hour;
   int utcMin  = utcDT.min;
   int utcDay  = utcDT.day_of_week; // 0=Sun,1=Mon,...,5=Fri,6=Sat

   //--- Force close at session end
   if(PositionSelect(_Symbol) &&
      PositionGetInteger(POSITION_MAGIC) == MagicNumber)
   {
      if(utcHour > SessionCloseHour ||
         (utcHour == SessionCloseHour && utcMin >= SessionCloseMin))
      {
         ClosePosition("SESSION_END");
         return;
      }
   }

   //--- Manage open position (trailing stops, TP levels)
   if(PositionSelect(_Symbol) &&
      PositionGetInteger(POSITION_MAGIC) == MagicNumber)
   {
      ManagePosition();
      return;
   }

   //--- Daily reset at midnight UTC
   static int lastDay = -1;
   if(utcDT.day != lastDay)
   {
      lastDay           = utcDT.day;
      rangeFormed       = false;
      tradeOpenedToday  = false;
      breakoutPending   = false;
      breakoutDir       = 0;
      rangeHigh         = 0;
      rangeLow          = 0;
      slDistance        = 0;
      cachedLots        = 0;
      beActivated       = false;
      tp1Hit            = false;
      tp2Hit            = false;
   }

   //--- Skip if trade already done today
   if(tradeOpenedToday) return;

   //--- Day filter
   if(!IsTradingDay(utcDay)) return;

   //--- New bar detection (M5)
   datetime currentBarTime = iTime(_Symbol, PERIOD_M5, 0);
   bool newBar = (currentBarTime != lastBarTime);
   if(newBar) lastBarTime = currentBarTime;

   //--- STEP 1: Calculate range at 14:50 UTC (after 14:45 candle closes)
   if(!rangeFormed && utcHour == 14 && utcMin >= 50)
   {
      if(newBar || !rangeFormed)
         TryCalculateRange(utcTime);
   }

   if(!rangeFormed) return;

   //--- STEP 2: Entry window check (14:50 to EntryWindowEnd_Min after 14:50)
   int entryWindowEndMin = 50 + EntryWindowEnd_Min; // e.g. 50+15=65 → 15:05
   int totalMinutes = utcHour * 60 + utcMin;
   int windowStart  = 14 * 60 + 50;
   int windowEnd    = 14 * 60 + entryWindowEndMin;

   if(totalMinutes < windowStart || totalMinutes >= windowEnd) return;

   //--- STEP 2A: Detect breakout (price crosses range)
   if(!breakoutPending)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      if(ask > rangeHigh)
      {
         breakoutPending    = true;
         breakoutDir        = 1; // BUY
         breakoutCandleTime = currentBarTime;
         Print("Breakout UP detected — waiting for candle close confirmation");
      }
      else if(bid < rangeLow)
      {
         breakoutPending    = true;
         breakoutDir        = -1; // SELL
         breakoutCandleTime = currentBarTime;
         Print("Breakout DOWN detected — waiting for candle close confirmation");
      }
   }

   //--- STEP 2B: Confirm on candle close
   if(breakoutPending && ConfirmOnClose)
   {
      // We wait for a NEW bar after the breakout candle
      if(currentBarTime != breakoutCandleTime)
      {
         // New candle opened — confirm price is still on breakout side
         double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
         double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

         bool confirmed = false;
         if(breakoutDir == 1  && ask > rangeHigh) confirmed = true;
         if(breakoutDir == -1 && bid < rangeLow)  confirmed = true;

         if(confirmed)
         {
            ExecuteTrade(breakoutDir);
         }
         else
         {
            Print("False breakout filtered — price returned to range");
            breakoutPending = false;
            breakoutDir     = 0;
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate the NY pre-session range (3 candles: 14:35/14:40/14:45)|
//+------------------------------------------------------------------+
void TryCalculateRange(datetime utcNow)
{
   // Find the 14:35, 14:40, 14:45 UTC candles
   // Server time = UTC + offset
   MqlDateTime sdt;

   // Build server timestamps for the 3 range candles
   TimeToStruct(utcNow, sdt);

   // We need today's date at 14:35/14:40/14:45 UTC → server time
   datetime base = StringToTime(
      StringFormat("%04d.%02d.%02d 00:00:00", sdt.year, sdt.mon, sdt.day));
   // This is midnight server time — we add UTC offset to get to UTC midnight
   // Actually build UTC midnight then convert
   MqlDateTime utcDT;
   TimeToStruct(utcNow, utcDT);
   datetime utcMidnight = StringToTime(
      StringFormat("%04d.%02d.%02d 00:00:00", utcDT.year, utcDT.mon, utcDT.day));

   datetime c1_utc = utcMidnight + 14*3600 + 35*60; // 14:35 UTC
   datetime c2_utc = utcMidnight + 14*3600 + 40*60; // 14:40 UTC
   datetime c3_utc = utcMidnight + 14*3600 + 45*60; // 14:45 UTC

   // Convert to server time
   datetime c1_srv = c1_utc + ServerOffsetHours * 3600;
   datetime c2_srv = c2_utc + ServerOffsetHours * 3600;
   datetime c3_srv = c3_utc + ServerOffsetHours * 3600;

   // Get bar indices
   int i1 = iBarShift(_Symbol, PERIOD_M5, c1_srv, false);
   int i2 = iBarShift(_Symbol, PERIOD_M5, c2_srv, false);
   int i3 = iBarShift(_Symbol, PERIOD_M5, c3_srv, false);

   if(i1 < 0 || i2 < 0 || i3 < 0)
   {
      Print("WARNING: Could not find range candles. i1=", i1, " i2=", i2, " i3=", i3);
      return;
   }

   // Verify these are actually the right candles (within 1 bar tolerance)
   double h1 = iHigh(_Symbol, PERIOD_M5, i1);
   double h2 = iHigh(_Symbol, PERIOD_M5, i2);
   double h3 = iHigh(_Symbol, PERIOD_M5, i3);
   double l1 = iLow(_Symbol, PERIOD_M5,  i1);
   double l2 = iLow(_Symbol, PERIOD_M5,  i2);
   double l3 = iLow(_Symbol, PERIOD_M5,  i3);

   // Range = full range of all 3 candles (NOT average, NOT 2 candles)
   rangeHigh = MathMax(h1, MathMax(h2, h3));
   rangeLow  = MathMin(l1, MathMin(l2, l3));

   // slDistance in _Points
   slDistance = (rangeHigh - rangeLow) / _Point;

   Print("Range formed — High: ", rangeHigh, " Low: ", rangeLow,
         " SL distance: ", slDistance, " pts");

   //--- Range filter
   if(slDistance < MinSL_Points)
   {
      Print("SKIP: Range too small (", slDistance, " < ", MinSL_Points, ")");
      rangeFormed = false;
      return;
   }
   if(slDistance > MaxSL_Points)
   {
      Print("SKIP: Range too large (", slDistance, " > ", MaxSL_Points, ")");
      rangeFormed = false;
      return;
   }

   //--- ATR filter
   if(ATR_FilterEnable && !CheckATRFilter())
   {
      Print("SKIP: ATR filter blocked this day");
      rangeFormed = false;
      return;
   }

   //--- Calculate lots ONCE here (cached)
   cachedLots = CalculateLotSize(slDistance);
   if(cachedLots <= 0)
   {
      Print("SKIP: Could not calculate valid lot size");
      rangeFormed = false;
      return;
   }

   rangeFormed = true;
   Print("Range valid. Lots cached: ", cachedLots);
}

//+------------------------------------------------------------------+
//| ATR Filter                                                       |
//+------------------------------------------------------------------+
bool CheckATRFilter()
{
   // Get current ATR value (bar 1 = last closed bar)
   double atrBuf[];
   ArraySetAsSeries(atrBuf, true);
   if(CopyBuffer(atrHandle, 0, 1, 1, atrBuf) <= 0) return true; // Skip filter if error

   double currentATR = atrBuf[0];

   // Calculate baseline ATR: average of ATR at 14:50 for last ATR_BaselineDays days
   // Simplified: use average of last ATR_BaselineDays*78 bars (78 M5 bars/day) ATR values
   int barsNeeded = ATR_BaselineDays * 78;
   double atrBaseline[];
   ArraySetAsSeries(atrBaseline, true);
   int copied = CopyBuffer(atrHandle, 0, 1, barsNeeded, atrBaseline);
   if(copied <= 0) return true;

   double sum = 0;
   for(int i = 0; i < copied; i++)
      sum += atrBaseline[i];
   double baselineATR = sum / copied;

   double atrMin = baselineATR * ATR_MinMultiplier;
   double atrMax = baselineATR * ATR_MaxMultiplier;

   Print("ATR check — Current: ", currentATR,
         " Baseline: ", baselineATR,
         " Min: ", atrMin, " Max: ", atrMax);

   if(currentATR < atrMin)
   {
      Print("ATR too low — no trade");
      return false;
   }
   if(currentATR > atrMax)
   {
      Print("ATR too high — no trade");
      return false;
   }
   return true;
}

//+------------------------------------------------------------------+
//| Calculate lot size                                               |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPts)
{
   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double volMin     = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volMax     = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double volStep    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   if(tickSize <= 0 || tickValue <= 0)
   {
      Print("ERROR: Invalid tick specs");
      return 0;
   }

   double valuePerPoint = tickValue / tickSize;  // USD per _Point per lot
   double lotsRaw       = RiskAmountUSD / (slPts * valuePerPoint);

   // Round down to VolumeStep
   double lots = MathFloor(lotsRaw / volStep) * volStep;
   lots = MathMax(lots, volMin);
   lots = MathMin(lots, volMax);

   // Actual risk after rounding
   double actualRisk = lots * slPts * valuePerPoint;
   Print("Lot calc — Raw: ", lotsRaw, " Rounded: ", lots,
         " ActualRisk: $", actualRisk);

   // Margin check
   double marginRequired = 0;
   if(!OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots,
      SymbolInfoDouble(_Symbol, SYMBOL_ASK), marginRequired))
   {
      Print("ERROR: OrderCalcMargin failed");
      return 0;
   }
   double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
   if(marginRequired > freeMargin * 0.90)
   {
      Print("ERROR: Insufficient margin. Required: ", marginRequired,
            " Free: ", freeMargin);
      return 0;
   }

   return lots;
}

//+------------------------------------------------------------------+
//| Execute trade                                                    |
//+------------------------------------------------------------------+
void ExecuteTrade(int direction)
{
   if(cachedLots <= 0) return;

   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist = slDistance * _Point;

   if(direction == 1) // BUY
   {
      entryPrice = ask;
      double sl  = NormalizeDouble(entryPrice - slDist, _Digits);
      double tp  = NormalizeDouble(entryPrice + slDist * TP3_RR, _Digits);

      tp1Level  = NormalizeDouble(entryPrice + slDist * TP1_RR, _Digits);
      tp2Level  = NormalizeDouble(entryPrice + slDist * TP2_RR, _Digits);
      tp3Level  = tp;
      beLevel   = NormalizeDouble(entryPrice + slDist * (BE_BufferPct/100.0), _Digits);
      originalSL = sl;

      if(trade.Buy(cachedLots, _Symbol, ask, sl, tp, "BreakoutNY_BUY"))
      {
         tradeOpenedToday = true;
         breakoutPending  = false;
         Print("BUY opened — Entry: ", entryPrice, " SL: ", sl, " TP3: ", tp,
               " Lots: ", cachedLots);
         LogTrade("BUY", entryPrice, sl, tp1Level, tp2Level, tp3Level, cachedLots);
      }
   }
   else // SELL
   {
      entryPrice = bid;
      double sl  = NormalizeDouble(entryPrice + slDist, _Digits);
      double tp  = NormalizeDouble(entryPrice - slDist * TP3_RR, _Digits);

      tp1Level  = NormalizeDouble(entryPrice - slDist * TP1_RR, _Digits);
      tp2Level  = NormalizeDouble(entryPrice - slDist * TP2_RR, _Digits);
      tp3Level  = tp;
      beLevel   = NormalizeDouble(entryPrice - slDist * (BE_BufferPct/100.0), _Digits);
      originalSL = sl;

      if(trade.Sell(cachedLots, _Symbol, bid, sl, tp, "BreakoutNY_SELL"))
      {
         tradeOpenedToday = true;
         breakoutPending  = false;
         Print("SELL opened — Entry: ", entryPrice, " SL: ", sl, " TP3: ", tp,
               " Lots: ", cachedLots);
         LogTrade("SELL", entryPrice, sl, tp1Level, tp2Level, tp3Level, cachedLots);
      }
   }
}

//+------------------------------------------------------------------+
//| Manage open position (BE + trailing)                             |
//+------------------------------------------------------------------+
void ManagePosition()
{
   if(!PositionSelect(_Symbol)) return;
   if(PositionGetInteger(POSITION_MAGIC) != MagicNumber) return;

   double currentPrice;
   double currentSL = PositionGetDouble(POSITION_SL);
   long   posType   = PositionGetInteger(POSITION_TYPE);
   double slDist    = slDistance * _Point;

   if(posType == POSITION_TYPE_BUY)
   {
      currentPrice = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      // Breakeven
      if(!beActivated && currentPrice >= beLevel)
      {
         double newSL = NormalizeDouble(entryPrice + slDist * (BE_BufferPct/100.0), _Digits);
         if(newSL > currentSL)
         {
            trade.PositionModify(_Symbol, newSL, tp3Level);
            beActivated = true;
            Print("BE activated — SL moved to: ", newSL);
         }
      }

      // TP1 hit → SL to entry + buffer
      if(!tp1Hit && currentPrice >= tp1Level)
      {
         tp1Hit = true;
         double newSL = NormalizeDouble(entryPrice + slDist * (BE_BufferPct/100.0), _Digits);
         if(newSL > currentSL)
            trade.PositionModify(_Symbol, newSL, tp3Level);

         if(EnablePartials)
         {
            double lotsToClose = NormalizeDouble(
               cachedLots * TP1_ClosePct / 100.0,
               2);
            if(lotsToClose >= SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN))
               trade.PositionClosePartial(_Symbol, lotsToClose);
         }
         Print("TP1 hit — SL at entry+buffer");
      }

      // TP2 hit → SL to TP1
      if(!tp2Hit && currentPrice >= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL > currentSL)
            trade.PositionModify(_Symbol, newSL, tp3Level);

         if(EnablePartials)
         {
            double lotsToClose = NormalizeDouble(
               cachedLots * TP2_ClosePct / 100.0,
               2);
            if(lotsToClose >= SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN))
               trade.PositionClosePartial(_Symbol, lotsToClose);
         }
         Print("TP2 hit — SL at TP1, guaranteed profit");
      }
   }
   else if(posType == POSITION_TYPE_SELL)
   {
      currentPrice = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

      // Breakeven
      if(!beActivated && currentPrice <= beLevel)
      {
         double newSL = NormalizeDouble(entryPrice - slDist * (BE_BufferPct/100.0), _Digits);
         if(newSL < currentSL)
         {
            trade.PositionModify(_Symbol, newSL, tp3Level);
            beActivated = true;
            Print("BE activated — SL moved to: ", newSL);
         }
      }

      // TP1 hit
      if(!tp1Hit && currentPrice <= tp1Level)
      {
         tp1Hit = true;
         double newSL = NormalizeDouble(entryPrice - slDist * (BE_BufferPct/100.0), _Digits);
         if(newSL < currentSL)
            trade.PositionModify(_Symbol, newSL, tp3Level);

         if(EnablePartials)
         {
            double lotsToClose = NormalizeDouble(
               cachedLots * TP1_ClosePct / 100.0,
               2);
            if(lotsToClose >= SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN))
               trade.PositionClosePartial(_Symbol, lotsToClose);
         }
         Print("TP1 hit — SL at entry+buffer");
      }

      // TP2 hit
      if(!tp2Hit && currentPrice <= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL < currentSL)
            trade.PositionModify(_Symbol, newSL, tp3Level);

         if(EnablePartials)
         {
            double lotsToClose = NormalizeDouble(
               cachedLots * TP2_ClosePct / 100.0,
               2);
            if(lotsToClose >= SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN))
               trade.PositionClosePartial(_Symbol, lotsToClose);
         }
         Print("TP2 hit — SL at TP1, guaranteed profit");
      }
   }
}

//+------------------------------------------------------------------+
//| Close position with reason                                       |
//+------------------------------------------------------------------+
void ClosePosition(string reason)
{
   if(!PositionSelect(_Symbol)) return;
   if(PositionGetInteger(POSITION_MAGIC) != MagicNumber) return;

   double profit = PositionGetDouble(POSITION_PROFIT);
   trade.PositionClose(_Symbol);
   Print("Position closed — Reason: ", reason, " PnL: $", profit);
}

//+------------------------------------------------------------------+
//| Day of week filter                                               |
//+------------------------------------------------------------------+
bool IsTradingDay(int dow)
{
   // dow: 1=Mon, 2=Tue, 3=Wed, 4=Thu, 5=Fri
   if(dow == 1 && !FilterMonday)    return false;
   if(dow == 2 && !FilterTuesday)   return false;
   if(dow == 3 && !FilterWednesday) return false;
   if(dow == 4 && !FilterThursday)  return false;
   if(dow == 5 && !FilterFriday)    return false;
   if(dow == 0 || dow == 6)         return false; // Weekend
   return true;
}

//+------------------------------------------------------------------+
//| Log trade to CSV                                                 |
//+------------------------------------------------------------------+
void LogTrade(string dir, double entry, double sl,
              double tp1, double tp2, double tp3, double lots)
{
   if(!EnableCSV || csvHandle == INVALID_HANDLE) return;

   datetime utcNow = TimeCurrent() - ServerOffsetHours * 3600;
   MqlDateTime dt;
   TimeToStruct(utcNow, dt);

   string dayNames[] = {"Sun","Mon","Tue","Wed","Thu","Fri","Sat"};
   string dayName = dayNames[dt.day_of_week];

   double atrBuf[];
   ArraySetAsSeries(atrBuf, true);
   double currentATR = 0, baselineATR = 0;
   if(CopyBuffer(atrHandle, 0, 1, 1, atrBuf) > 0) currentATR = atrBuf[0];

   double actualRisk = lots * slDistance *
      (SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE) /
       SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE));

   FileWrite(csvHandle,
      TimeToString(utcNow, TIME_DATE),
      dayName, dir,
      DoubleToString(entry, _Digits),
      DoubleToString(sl, _Digits),
      DoubleToString(tp1, _Digits),
      DoubleToString(tp2, _Digits),
      DoubleToString(tp3, _Digits),
      DoubleToString(lots, 2),
      DoubleToString(actualRisk, 2),
      "", "", "",  // ExitPrice, ExitReason, PnL filled on close
      DoubleToString(slDistance, 0),
      DoubleToString(currentATR, 2),
      DoubleToString(baselineATR, 2));
   FileFlush(csvHandle);
}
