//+------------------------------------------------------------------+
//|  BreakoutNY_Calibrator_DJI30.mq5                                |
//|  Calibration script — DJI30 NY Pre-Session Range Analysis       |
//|  Calculates P5/P25/Median/P75/P95 of range across last 3 years  |
//|  Output: BreakoutNY_Calibration_DJI30.csv                       |
//|                                                                  |
//|  HOW TO USE:                                                     |
//|    1. Attach to DJI30 M5 chart                                   |
//|    2. Run script                                                 |
//|    3. Open BreakoutNY_Calibration_DJI30.csv in Excel            |
//|    4. Set MinSL_Points = P25, MaxSL_Points = P75                |
//+------------------------------------------------------------------+
#property script_show_inputs

input int    ServerOffsetHours = 2;     // UTC offset (UTC+2 FundingPips)
input int    LookbackDays      = 756;   // ~3 years of trading days
input string OutputFile        = "BreakoutNY_Calibration_DJI30.csv";

void OnStart()
{
   Print("=== BreakoutNY DJI30 Range Calibrator ===");
   Print("Symbol: ", _Symbol, " | ServerOffset: UTC+", ServerOffsetHours);

   if(_Symbol != "DJI30")
      Print("WARNING: Running on ", _Symbol, " — expected DJI30");

   // Arrays to store daily range data
   double ranges[];
   string dates[];
   string days[];
   ArrayResize(ranges, 0);
   ArrayResize(dates, 0);
   ArrayResize(days, 0);

   int totalBars = iBars(_Symbol, PERIOD_M5);
   Print("Total M5 bars available: ", totalBars);

   // Scan backwards through history
   int daysProcessed = 0;
   int daysSkipped   = 0;
   datetime lastDate = 0;

   for(int b = 1; b < totalBars - 10 && daysProcessed < LookbackDays; b++)
   {
      datetime barTime = iTime(_Symbol, PERIOD_M5, b);
      datetime utcTime = barTime - ServerOffsetHours * 3600;

      MqlDateTime utcDT;
      TimeToStruct(utcTime, utcDT);

      // We're looking for the 14:45 UTC candle (server: 16:45 UTC+2)
      if(utcDT.hour != 14 || utcDT.min != 45) continue;

      // Skip weekends
      if(utcDT.day_of_week == 0 || utcDT.day_of_week == 6) continue;

      // Skip duplicate dates
      datetime thisDate = StringToTime(
         StringFormat("%04d.%02d.%02d", utcDT.year, utcDT.mon, utcDT.day));
      if(thisDate == lastDate) continue;
      lastDate = thisDate;

      // Find the 14:35 and 14:40 candles
      datetime utcMidnight = thisDate - (ServerOffsetHours * 3600);
      // Actually just compute server times for the 3 range candles
      datetime c1_utc = thisDate + (14*3600 + 35*60) - (ServerOffsetHours*3600);
      // Wait — thisDate is already in server time as midnight server
      // Recompute properly:
      MqlDateTime d;
      TimeToStruct(barTime, d); // barTime is 16:45 server time
      datetime srvMidnight = StringToTime(
         StringFormat("%04d.%02d.%02d 00:00:00", d.year, d.mon, d.day));

      datetime c1_srv = srvMidnight + (14 + ServerOffsetHours)*3600 + 35*60; // 16:35 srv
      datetime c2_srv = srvMidnight + (14 + ServerOffsetHours)*3600 + 40*60; // 16:40 srv
      datetime c3_srv = srvMidnight + (14 + ServerOffsetHours)*3600 + 45*60; // 16:45 srv

      int i1 = iBarShift(_Symbol, PERIOD_M5, c1_srv, false);
      int i2 = iBarShift(_Symbol, PERIOD_M5, c2_srv, false);
      int i3 = iBarShift(_Symbol, PERIOD_M5, c3_srv, false);

      if(i1 < 0 || i2 < 0 || i3 < 0)
      {
         daysSkipped++;
         continue;
      }

      // Verify bar times are correct (within 1 bar)
      datetime t1 = iTime(_Symbol, PERIOD_M5, i1);
      datetime t2 = iTime(_Symbol, PERIOD_M5, i2);
      datetime t3 = iTime(_Symbol, PERIOD_M5, i3);

      // Allow 1 bar tolerance (300 seconds)
      if(MathAbs((int)(t1 - c1_srv)) > 300 ||
         MathAbs((int)(t2 - c2_srv)) > 300 ||
         MathAbs((int)(t3 - c3_srv)) > 300)
      {
         daysSkipped++;
         continue;
      }

      double h1 = iHigh(_Symbol, PERIOD_M5, i1);
      double h2 = iHigh(_Symbol, PERIOD_M5, i2);
      double h3 = iHigh(_Symbol, PERIOD_M5, i3);
      double l1 = iLow(_Symbol,  PERIOD_M5, i1);
      double l2 = iLow(_Symbol,  PERIOD_M5, i2);
      double l3 = iLow(_Symbol,  PERIOD_M5, i3);

      double rHigh = MathMax(h1, MathMax(h2, h3));
      double rLow  = MathMin(l1, MathMin(l2, l3));
      double range = (rHigh - rLow) / _Point; // In _Points

      if(range <= 0) { daysSkipped++; continue; }

      // Store result
      int sz = ArraySize(ranges);
      ArrayResize(ranges, sz + 1);
      ArrayResize(dates,  sz + 1);
      ArrayResize(days,   sz + 1);

      ranges[sz] = range;
      dates[sz]  = StringFormat("%04d.%02d.%02d", utcDT.year, utcDT.mon, utcDT.day);

      string dayNames[] = {"Sun","Mon","Tue","Wed","Thu","Fri","Sat"};
      days[sz] = dayNames[utcDT.day_of_week];

      daysProcessed++;
   }

   Print("Days processed: ", daysProcessed, " | Skipped: ", daysSkipped);

   if(daysProcessed < 30)
   {
      Print("ERROR: Not enough data. Download more M5 history for DJI30.");
      return;
   }

   // Sort ranges for percentile calculation
   double sorted[];
   ArrayCopy(sorted, ranges);
   ArraySort(sorted);

   int n = ArraySize(sorted);

   // Calculate percentiles
   double p5   = sorted[(int)MathRound(n * 0.05)];
   double p10  = sorted[(int)MathRound(n * 0.10)];
   double p25  = sorted[(int)MathRound(n * 0.25)];
   double p50  = sorted[(int)MathRound(n * 0.50)];
   double mean = 0;
   for(int i = 0; i < n; i++) mean += sorted[i];
   mean /= n;
   double p75  = sorted[(int)MathRound(n * 0.75)];
   double p90  = sorted[(int)MathRound(n * 0.90)];
   double p95  = sorted[(int)MathRound(n * 0.95)];
   double pMax = sorted[n-1];
   double pMin = sorted[0];

   // Print summary
   Print("=== RANGE PERCENTILES (in _Points) ===");
   Print("Min   : ", pMin);
   Print("P5    : ", p5);
   Print("P10   : ", p10);
   Print("P25   : ", p25, "  ← Recommended MinSL_Points");
   Print("Median: ", p50);
   Print("Mean  : ", mean);
   Print("P75   : ", p75, "  ← Recommended MaxSL_Points");
   Print("P90   : ", p90);
   Print("P95   : ", p95);
   Print("Max   : ", pMax);
   Print("=======================================");
   Print("RECOMMENDATION:");
   Print("  MinSL_Points = ", p25, " (P25)");
   Print("  MaxSL_Points = ", p75, " (P75)");

   // Write main summary CSV
   int fh = FileOpen(OutputFile, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(fh == INVALID_HANDLE)
   {
      Print("ERROR: Cannot open output file ", OutputFile);
      return;
   }

   // Summary section
   FileWrite(fh, "=== BREAKOUTNY DJI30 RANGE CALIBRATION ===");
   FileWrite(fh, "Symbol", _Symbol);
   FileWrite(fh, "ServerOffset", StringFormat("UTC+%d", ServerOffsetHours));
   FileWrite(fh, "LookbackDays", LookbackDays);
   FileWrite(fh, "DaysAnalyzed", daysProcessed);
   FileWrite(fh, "");
   FileWrite(fh, "=== PERCENTILES (_Points) ===");
   FileWrite(fh, "Percentile", "Value_Points", "Recommendation");
   FileWrite(fh, "Min",    DoubleToString(pMin, 0), "");
   FileWrite(fh, "P5",     DoubleToString(p5,   0), "");
   FileWrite(fh, "P10",    DoubleToString(p10,  0), "");
   FileWrite(fh, "P25",    DoubleToString(p25,  0), "<<< MinSL_Points");
   FileWrite(fh, "Median", DoubleToString(p50,  0), "");
   FileWrite(fh, "Mean",   DoubleToString(mean, 0), "");
   FileWrite(fh, "P75",    DoubleToString(p75,  0), "<<< MaxSL_Points");
   FileWrite(fh, "P90",    DoubleToString(p90,  0), "");
   FileWrite(fh, "P95",    DoubleToString(p95,  0), "");
   FileWrite(fh, "Max",    DoubleToString(pMax, 0), "");
   FileWrite(fh, "");

   // Day-of-week breakdown
   string dowNames[] = {"Mon","Tue","Wed","Thu","Fri"};
   int    dowIds[]   = {1, 2, 3, 4, 5};

   FileWrite(fh, "=== BY DAY OF WEEK ===");
   FileWrite(fh, "Day", "Count", "Mean_Pts", "Median_Pts", "P25_Pts", "P75_Pts");

   for(int d = 0; d < 5; d++)
   {
      double dowRanges[];
      ArrayResize(dowRanges, 0);

      for(int i = 0; i < ArraySize(ranges); i++)
      {
         if(days[i] == dowNames[d])
         {
            int sz = ArraySize(dowRanges);
            ArrayResize(dowRanges, sz + 1);
            dowRanges[sz] = ranges[i];
         }
      }

      if(ArraySize(dowRanges) == 0) continue;

      ArraySort(dowRanges);
      int nd = ArraySize(dowRanges);
      double dowMean = 0;
      for(int i = 0; i < nd; i++) dowMean += dowRanges[i];
      dowMean /= nd;

      FileWrite(fh,
         dowNames[d],
         nd,
         DoubleToString(dowMean, 0),
         DoubleToString(dowRanges[(int)MathRound(nd*0.50)], 0),
         DoubleToString(dowRanges[(int)MathRound(nd*0.25)], 0),
         DoubleToString(dowRanges[(int)MathRound(nd*0.75)], 0));
   }

   FileWrite(fh, "");

   // Raw data
   FileWrite(fh, "=== RAW DATA ===");
   FileWrite(fh, "Date", "DayOfWeek", "Range_Points");
   for(int i = 0; i < ArraySize(ranges); i++)
      FileWrite(fh, dates[i], days[i], DoubleToString(ranges[i], 0));

   FileFlush(fh);
   FileClose(fh);

   Print("Output written to: ", OutputFile);
   Print("=== CALIBRATION COMPLETE ===");
}
