   // Summary section
   FileWrite(fh, "=== BREAKOUTNY DJI30 RANGE CALIBRATION ===");
   FileWrite(fh, "Symbol", _Symbol);
   FileWrite(fh, "ServerOffset", StringFormat("UTC+%d", ServerOffsetHours));
   FileWrite(fh, "LookbackDays", LookbackDays);
   FileWrite(fh, "DaysAnalyzed", daysProcessed);
   FileWrite(fh, "");
   FileWrite(fh, "=== PERCENTILES (_Points) ===");
   FileWrite(fh, "Percentile", "Value_Points", "Recommendation");
   FileWrite(fh, "Min",    DoubleToString(pMin, 0), "");
   FileWrite(fh, "P5",     DoubleToString(p5,   0), "");
   FileWrite(fh, "P10",    DoubleToString(p10,  0), "");
   FileWrite(fh, "P25",    DoubleToString(p25,  0), "<<< MinSL_Points");
   FileWrite(fh, "Median", DoubleToString(p50,  0), "");
   FileWrite(fh, "Mean",   DoubleToString(mean, 0), "");
   FileWrite(fh, "P75",    DoubleToString(p75,  0), "<<< MaxSL_Points");
   FileWrite(fh, "P90",    DoubleToString(p90,  0), "");
   FileWrite(fh, "P95",    DoubleToString(p95,  0), "");
   FileWrite(fh, "Max",    DoubleToString(pMax, 0), "");
   FileWrite(fh, "");

   // Day-of-week breakdown
   string dowNames[] = {"Mon","Tue","Wed","Thu","Fri"};
   int    dowIds[]   = {1, 2, 3, 4, 5};

   FileWrite(fh, "=== BY DAY OF WEEK ===");
   FileWrite(fh, "Day", "Count", "Mean_Pts", "Median_Pts", "P25_Pts", "P75_Pts");

   for(int d = 0; d < 5; d++)
   {
      double dowRanges[];
      ArrayResize(dowRanges, 0);

      for(int i = 0; i < ArraySize(ranges); i++)
      {
         if(days[i] == dowNames[d])
         {
            int sz = ArraySize(dowRanges);
            ArrayResize(dowRanges, sz + 1);
            dowRanges[sz] = ranges[i];
         }
      }

      if(ArraySize(dowRanges) == 0) continue;

      ArraySort(dowRanges);
      int nd = ArraySize(dowRanges);
      double dowMean = 0;
      for(int i = 0; i < nd; i++) dowMean += dowRanges[i];
      dowMean /= nd;

      FileWrite(fh,
         dowNames[d],
         nd,
         DoubleToString(dowMean, 0),
         DoubleToString(dowRanges[(int)MathRound(nd*0.50)], 0),
         DoubleToString(dowRanges[(int)MathRound(nd*0.25)], 0),
         DoubleToString(dowRanges[(int)MathRound(nd*0.75)], 0));
   }

   FileWrite(fh, "");

   // Raw data
   FileWrite(fh, "=== RAW DATA ===");
   FileWrite(fh, "Date", "DayOfWeek", "Range_Points");
   for(int i = 0; i < ArraySize(ranges); i++)
      FileWrite(fh, dates[i], days[i], DoubleToString(ranges[i], 0));

   FileFlush(fh);
   FileClose(fh);

   Print("Output written to: ", OutputFile);
   Print("=== CALIBRATION COMPLETE ===");
