         }
      }

      // TP1 hit → SL to entry + buffer
      if(!tp1Hit && currentPrice >= tp1Level)
      {
         tp1Hit = true;
         double newSL = NormalizeDouble(entryPrice + slDist * (BE_BufferPct/100.0), _Digits);
         if(newSL > currentSL)
            trade.PositionModify(_Symbol, newSL, tp3Level);

         if(EnablePartials)
         {
            double lotsToClose = NormalizeDouble(
               cachedLots * TP1_ClosePct / 100.0,
