            if(lotsToClose >= SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN))
               trade.PositionClosePartial(_Symbol, lotsToClose);
         }
         Print("TP1 hit — SL at entry+buffer");
      }

      // TP2 hit → SL to TP1
      if(!tp2Hit && currentPrice >= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL > currentSL)
            trade.PositionModify(_Symbol, newSL, tp3Level);

         if(EnablePartials)
         {
            double lotsToClose = NormalizeDouble(
