int      csvHandle          = INVALID_HANDLE;

// Bar tracking
datetime lastBarTime        = 0;

// Daily reset tracker
int      lastResetDay       = -1;

//+------------------------------------------------------------------+
//| Expert initialization                                            |
//+------------------------------------------------------------------+
int OnInit()
{
   //--- Validate TP ratios
   if(TP1_RR <= 0 || TP2_RR <= TP1_RR || TP3_RR <= TP2_RR)
   {
      Print("ERROR: Invalid TP ratios. Must be: 0 < TP1 < TP2 < TP3");
      return(INIT_FAILED);
   }

   trade.SetExpertMagicNumber(MagicNumber);
   trade.SetDeviationInPoints(20);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   //--- Print verified contract specs
   double ts  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double tv  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double cs  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   double vpp = (ts > 0) ? tv / ts : 0;

   Print("=== BreakoutNY v2.0 DJI30 FundingPips ===");
   Print("Symbol        : ", _Symbol);
   Print("ContractSize  : ", cs);
   Print("TickSize      : ", ts);
   Print("TickValue     : ", tv);
   Print("Point         : ", _Point);
   Print("VolumeMin     : ", SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN));
   Print("VolumeStep    : ", SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP));
   Print("ValuePerPoint : $", vpp, "/_Point/lot");
   Print("RiskAmountUSD : $", RiskAmountUSD);
   Print("ServerOffset  : UTC+", ServerOffsetHours);
   Print("--- Trade management ---");
   Print("TP1 (SL→entry): ", TP1_RR, "R");
   Print("TP2 (SL→TP1)  : ", TP2_RR, "R");
   Print("TP3 (target)  : ", TP3_RR, "R");
   Print("FilterWed     : ", FilterWednesday ? "ON" : "OFF (recommended)");
   Print("ATR_MinMult   : ", ATR_MinMultiplier);
   Print("==========================================");

   //--- Verify M5
   if(_Period != PERIOD_M5)
   {
      Print("ERROR: Must run on M5. Current: ", EnumToString(_Period));
      return(INIT_FAILED);
   }

   //--- Sanity check: warn if running on wrong symbol
   if(_Symbol != "DJI30")
      Print("WARNING: Running on ", _Symbol, " — expected DJI30");

   //--- ATR
   atrHandle = iATR(_Symbol, PERIOD_M5, ATR_Period);
   if(atrHandle == INVALID_HANDLE)
   {
      Print("ERROR: Failed to create ATR handle");
      return(INIT_FAILED);
   }

   //--- CSV with append mode (survives EA restart)
   if(EnableCSV)
   {
      string path = CSVFileName + ".csv";
      // Try append first; create new if doesn't exist
      csvHandle = FileOpen(path, FILE_READ|FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
      if(csvHandle != INVALID_HANDLE)
      {
         FileSeek(csvHandle, 0, SEEK_END);
         if(FileTell(csvHandle) == 0) // New file
         {
            FileWrite(csvHandle,
               "Date","Day","Direction","EntryPrice","SL_Original",
               "TP1","TP2","TP3","Lots","RiskUSD_Est",
               "ExitPrice","ExitReason","PnL_USD",
               "SL_Dist_Pts","ATR_Current","ATR_Baseline",
               "HoldTime_Min");
         }
         FileFlush(csvHandle);
      }
      else
      {
         Print("WARNING: Could not open CSV file — logging disabled");
      }
   }

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization                                          |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if(csvHandle != INVALID_HANDLE) { FileFlush(csvHandle); FileClose(csvHandle); }
   if(atrHandle != INVALID_HANDLE) IndicatorRelease(atrHandle);
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   datetime serverTime = TimeCurrent();
   datetime utcTime    = serverTime - ServerOffsetHours * 3600;

   MqlDateTime utcDT;
   TimeToStruct(utcTime, utcDT);
   int utcHour = utcDT.hour;
   int utcMin  = utcDT.min;
   int utcDay  = utcDT.day_of_week;

   //--- Daily reset (UTC midnight)
   if(utcDT.day != lastResetDay)
   {
      lastResetDay      = utcDT.day;
      rangeFormed       = false;
      tradeOpenedToday  = false;
      breakoutPending   = false;
      breakoutDir       = 0;
      rangeHigh         = 0;
      rangeLow          = 0;
      slDistance        = 0;
      cachedLots        = 0;
      tp1Hit            = false;
      tp2Hit            = false;
      tradeDirection    = 0;
      originalSL        = 0;
      entryPrice        = 0;
   }

   //--- Force close at session end (17:00 UTC)
   if(HasOpenPosition())
   {
      if(utcHour > SessionCloseHour ||
         (utcHour == SessionCloseHour && utcMin >= SessionCloseMin))
      {
         ClosePosition("SESSION_END");
         return;
      }
      //--- Manage trailing stops for open position
      ManagePosition();
      return;
   }

   //--- Skip if trade done today or non-trading day
   if(tradeOpenedToday) return;
   if(!IsTradingDay(utcDay)) return;

   //--- New bar detection
   datetime currentBarTime = iTime(_Symbol, PERIOD_M5, 0);
   bool newBar = (currentBarTime != lastBarTime);
   if(newBar) lastBarTime = currentBarTime;

   //--- STEP 1: Calculate range at 14:50 UTC (after 14:45 bar closes)
   if(!rangeFormed)
   {
      int totalMin = utcHour * 60 + utcMin;
      if(totalMin >= 14 * 60 + 50)
         TryCalculateRange(utcTime);
   }

   if(!rangeFormed) return;

   //--- STEP 2: Entry window — 14:50 to (14:50 + EntryWindowEnd_Min)
   int totalMin    = utcHour * 60 + utcMin;
   int windowStart = 14 * 60 + 50;
   int windowEnd   = windowStart + EntryWindowEnd_Min;
   if(totalMin < windowStart || totalMin >= windowEnd) return;

   //--- STEP 2A: Detect initial breakout
   if(!breakoutPending)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      if(ask > rangeHigh)
      {
         breakoutPending    = true;
         breakoutDir        = 1;
         breakoutCandleTime = currentBarTime;
         Print("Breakout UP detected at ", ask, " — waiting for candle close");
      }
      else if(bid < rangeLow)
      {
         breakoutPending    = true;
         breakoutDir        = -1;
         breakoutCandleTime = currentBarTime;
         Print("Breakout DOWN detected at ", bid, " — waiting for candle close");
      }
   }

   //--- STEP 2B: Confirm on candle close (ConfirmOnClose always true)
   if(breakoutPending)
   {
      // Wait for the bar AFTER the breakout candle
      if(currentBarTime != breakoutCandleTime)
      {
         double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
         double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

         bool confirmed = false;
         if(breakoutDir ==  1 && ask > rangeHigh) confirmed = true;
         if(breakoutDir == -1 && bid < rangeLow)  confirmed = true;

         if(confirmed)
         {
            ExecuteTrade(breakoutDir);
         }
         else
         {
            Print("False breakout — price returned to range. Skipping.");
            breakoutPending = false;
            breakoutDir     = 0;
         }
      }
   }
}

//+------------------------------------------------------------------+
//| OnTradeTransaction — capture exit data for CSV                  |
//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest     &request,
                        const MqlTradeResult      &result)
{
   // Only interested in deal adds (position close)
   if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;

   ulong dealTicket = trans.deal;
   if(dealTicket <= 0) return;

   if(HistoryDealSelect(dealTicket))
   {
      long   magic      = HistoryDealGetInteger(dealTicket, DEAL_MAGIC);
      long   dealEntry  = HistoryDealGetInteger(dealTicket, DEAL_ENTRY);
      if(magic != MagicNumber) return;
      if(dealEntry != DEAL_ENTRY_OUT) return; // Only closing deals

      double exitPrice  = HistoryDealGetDouble(dealTicket, DEAL_PRICE);
      double profit     = HistoryDealGetDouble(dealTicket, DEAL_PROFIT);
      string comment    = HistoryDealGetString(dealTicket, DEAL_COMMENT);

      // Determine exit reason
      string exitReason = "UNKNOWN";
      if(StringFind(comment, "sl") >= 0)     exitReason = "SL";
      else if(StringFind(comment, "tp") >= 0) exitReason = "TP";
      else                                    exitReason = "SESSION_END";

      UpdateCSVExit(exitPrice, exitReason, profit);
   }
}

//+------------------------------------------------------------------+
//| Calculate NY pre-session range (3 candles: 14:35/14:40/14:45)   |
//+------------------------------------------------------------------+
void TryCalculateRange(datetime utcNow)
{
   MqlDateTime utcDT;
   TimeToStruct(utcNow, utcDT);

   // Build server timestamps for the 3 range candles
   datetime srvMidnight = StringToTime(
      StringFormat("%04d.%02d.%02d 00:00:00",
         utcDT.year, utcDT.mon, utcDT.day));
   // srvMidnight is midnight in server time
   // UTC offset already applied when we compute server time:
   // server_time = utc_time + offset, so:
   datetime c1_srv = srvMidnight + (14 + ServerOffsetHours)*3600 + 35*60;
   datetime c2_srv = srvMidnight + (14 + ServerOffsetHours)*3600 + 40*60;
   datetime c3_srv = srvMidnight + (14 + ServerOffsetHours)*3600 + 45*60;

   // Wait — srvMidnight is already in server TZ.
   // utcDT was derived from utcTime = serverTime - offset*3600
   // So utcDT.day = server day if offset doesn't cross midnight
   // Recompute properly using actual server time
   datetime serverNow = TimeCurrent();
   MqlDateTime srvDT;
   TimeToStruct(serverNow, srvDT);
   datetime srvMid2 = StringToTime(
      StringFormat("%04d.%02d.%02d 00:00:00",
         srvDT.year, srvDT.mon, srvDT.day));

   c1_srv = srvMid2 + (14 + ServerOffsetHours)*3600 + 35*60;
   c2_srv = srvMid2 + (14 + ServerOffsetHours)*3600 + 40*60;
   c3_srv = srvMid2 + (14 + ServerOffsetHours)*3600 + 45*60;

   int i1 = iBarShift(_Symbol, PERIOD_M5, c1_srv, false);
   int i2 = iBarShift(_Symbol, PERIOD_M5, c2_srv, false);
   int i3 = iBarShift(_Symbol, PERIOD_M5, c3_srv, false);

   if(i1 < 0 || i2 < 0 || i3 < 0)
   {
      Print("Range candles not found. i1=", i1, " i2=", i2, " i3=", i3);
      return;
   }

   // Verify bar timestamps (within 1 bar = 300 seconds)
   datetime t1 = iTime(_Symbol, PERIOD_M5, i1);
   datetime t2 = iTime(_Symbol, PERIOD_M5, i2);
   datetime t3 = iTime(_Symbol, PERIOD_M5, i3);
   if(MathAbs((int)(t1-c1_srv))>300 || MathAbs((int)(t2-c2_srv))>300 || MathAbs((int)(t3-c3_srv))>300)
   {
      Print("Range candle mismatch. Check ServerOffsetHours.");
      return;
   }

   // Range = full span of all 3 candles (not average, not 2 candles)
   double h1 = iHigh(_Symbol, PERIOD_M5, i1);
   double h2 = iHigh(_Symbol, PERIOD_M5, i2);
   double h3 = iHigh(_Symbol, PERIOD_M5, i3);
   double l1 = iLow(_Symbol,  PERIOD_M5, i1);
   double l2 = iLow(_Symbol,  PERIOD_M5, i2);
   double l3 = iLow(_Symbol,  PERIOD_M5, i3);

   rangeHigh  = MathMax(h1, MathMax(h2, h3));
   rangeLow   = MathMin(l1, MathMin(l2, l3));
   slDistance = (rangeHigh - rangeLow) / _Point;

   Print("Range: H=", rangeHigh, " L=", rangeLow, " SL=", slDistance, " pts");

   //--- Range filter
   if(slDistance < MinSL_Points)
   { Print("SKIP: Range too small (", slDistance, " < ", MinSL_Points, ")"); return; }
   if(slDistance > MaxSL_Points)
   { Print("SKIP: Range too large (", slDistance, " > ", MaxSL_Points, ")"); return; }

   //--- ATR filter
   if(ATR_FilterEnable && !CheckATRFilter())
   { Print("SKIP: ATR filter blocked"); return; }

   //--- Calculate lots once
   cachedLots = CalculateLotSize(slDistance);
   if(cachedLots <= 0)
   { Print("SKIP: Could not calculate valid lots"); return; }

   rangeFormed = true;
   Print("Range valid. Lots=", cachedLots, " RiskEst=$",
         cachedLots * slDistance * (SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE) /
                                    SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE)));
}

//+------------------------------------------------------------------+
//| ATR baseline filter                                              |
//+------------------------------------------------------------------+
bool CheckATRFilter()
{
   double atrBuf[];
   ArraySetAsSeries(atrBuf, true);

   if(CopyBuffer(atrHandle, 0, 1, 1, atrBuf) <= 0) return true;
   double currentATR = atrBuf[0];

   // Baseline = average of last ATR_BaselineDays × 78 bars (78 M5 per day)
   int barsNeeded = ATR_BaselineDays * 78;
   double atrBase[];
   ArraySetAsSeries(atrBase, true);
   int copied = CopyBuffer(atrHandle, 0, 1, barsNeeded, atrBase);
   if(copied <= 10) return true;

   double sum = 0;
   for(int i = 0; i < copied; i++) sum += atrBase[i];
   double baseline = sum / copied;

   double atrMin = baseline * ATR_MinMultiplier;
   double atrMax = baseline * ATR_MaxMultiplier;

   Print("ATR: current=", currentATR, " baseline=", baseline,
         " range=[", atrMin, ",", atrMax, "]");

   if(currentATR < atrMin) { Print("ATR too low"); return false; }
   if(currentATR > atrMax) { Print("ATR too high"); return false; }
   return true;
}

//+------------------------------------------------------------------+
//| Lot size calculation                                             |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPts)
{
   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double volMin     = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volMax     = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double volStep    = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   if(tickSize <= 0 || tickValue <= 0) { Print("ERROR: Invalid tick specs"); return 0; }

   double vpp     = tickValue / tickSize;  // USD per _Point per lot
   double lotsRaw = RiskAmountUSD / (slPts * vpp);

   // Round DOWN to nearest VolumeStep, then clamp
   double lots = MathFloor(lotsRaw / volStep) * volStep;
   lots = MathMax(lots, volMin);
   lots = MathMin(lots, volMax);

   double actualRisk = lots * slPts * vpp;
   Print("Lots: raw=", lotsRaw, " rounded=", lots, " actualRisk=$", actualRisk);

   // Margin check (90% of free margin limit)
   double marginReq = 0;
   if(!OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots,
                       SymbolInfoDouble(_Symbol, SYMBOL_ASK), marginReq))
   { Print("ERROR: OrderCalcMargin failed"); return 0; }

   double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
   if(marginReq > freeMargin * 0.90)
   { Print("ERROR: Insufficient margin. Need=", marginReq, " Free=", freeMargin); return 0; }

   return lots;
}

//+------------------------------------------------------------------+
//| Execute trade entry                                              |
//+------------------------------------------------------------------+
void ExecuteTrade(int direction)
{
   if(cachedLots <= 0) return;

   double ask      = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid      = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDist   = slDistance * _Point;

   tradeDirection  = direction;

   if(direction == 1) // BUY
   {
      entryPrice = ask;
      double sl  = NormalizeDouble(entryPrice - slDist,           _Digits);
      double tp1 = NormalizeDouble(entryPrice + slDist * TP1_RR,  _Digits);
      double tp2 = NormalizeDouble(entryPrice + slDist * TP2_RR,  _Digits);
      double tp3 = NormalizeDouble(entryPrice + slDist * TP3_RR,  _Digits);

      originalSL = sl;
      tp1Level   = tp1;
      tp2Level   = tp2;
      tp3Level   = tp3;

      // Place order with TP3 as the hard take-profit
      if(trade.Buy(cachedLots, _Symbol, ask, sl, tp3, "BreakoutNY_BUY"))
      {
         tradeOpenedToday = true;
         breakoutPending  = false;
         tp1Hit           = false;
         tp2Hit           = false;
         Print("BUY | Entry=", entryPrice, " SL=", sl,
               " TP1=", tp1, " TP2=", tp2, " TP3=", tp3,
               " Lots=", cachedLots);
         LogTradeEntry("BUY", entryPrice, sl, tp1, tp2, tp3, cachedLots);
      }
   }
   else // SELL
   {
      entryPrice = bid;
      double sl  = NormalizeDouble(entryPrice + slDist,           _Digits);
      double tp1 = NormalizeDouble(entryPrice - slDist * TP1_RR,  _Digits);
      double tp2 = NormalizeDouble(entryPrice - slDist * TP2_RR,  _Digits);
      double tp3 = NormalizeDouble(entryPrice - slDist * TP3_RR,  _Digits);

      originalSL = sl;
      tp1Level   = tp1;
      tp2Level   = tp2;
      tp3Level   = tp3;

      if(trade.Sell(cachedLots, _Symbol, bid, sl, tp3, "BreakoutNY_SELL"))
      {
         tradeOpenedToday = true;
         breakoutPending  = false;
         tp1Hit           = false;
         tp2Hit           = false;
         Print("SELL | Entry=", entryPrice, " SL=", sl,
               " TP1=", tp1, " TP2=", tp2, " TP3=", tp3,
               " Lots=", cachedLots);
         LogTradeEntry("SELL", entryPrice, sl, tp1, tp2, tp3, cachedLots);
      }
   }
}

//+------------------------------------------------------------------+
//| ManagePosition — v2 BE logic                                     |
//|                                                                  |
//| KEY CHANGE FROM v1:                                              |
//| The old code had a single "beLevel" computed as                  |
//|   entry + slDist * (BE_BufferPct/100)                           |
//| When BE_BufferPct=0, beLevel = entry = instantly triggered.      |
//| When BE_BufferPct=20, beLevel was only 20% into the move.        |
//| When BE_BufferPct=80, beLevel required 80% of the SL distance.   |
//|                                                                  |
//| v2 approach: NO separate BE level. The SL is locked at the       |
//| original stop until TP1 is hit. Only then does it move.         |
//|   TP1 hit → SL moves to entry (zero risk)                       |
//|   TP2 hit → SL moves to TP1 (minimum profit locked)             |
//|   TP3     → closed by hard stop (set at entry)                  |
//+------------------------------------------------------------------+
void ManagePosition()
{
   if(!HasOpenPosition()) return;

   double currentSL  = PositionGetDouble(POSITION_SL);
   long   posType    = PositionGetInteger(POSITION_TYPE);

   if(posType == POSITION_TYPE_BUY)
   {
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      // ── TP1 reached → SL moves to entry (trade becomes risk-free) ──
      if(!tp1Hit && bid >= tp1Level)
      {
         tp1Hit = true;
         double newSL = NormalizeDouble(entryPrice, _Digits);
         if(newSL > currentSL + _Point)
         {
            trade.PositionModify(_Symbol, newSL, tp3Level);
            Print("TP1 hit BUY | SL → entry (", newSL, ") trade is risk-free");
         }
         if(EnablePartials) DoPartialClose(TP1_ClosePct);
      }

      // ── TP2 reached → SL moves to TP1 (profit locked) ──
      if(!tp2Hit && bid >= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL > currentSL + _Point)
         {
            trade.PositionModify(_Symbol, newSL, tp3Level);
            Print("TP2 hit BUY | SL → TP1 (", newSL, ") profit locked");
         }
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
   else if(posType == POSITION_TYPE_SELL)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

      // ── TP1 reached → SL moves to entry ──
      if(!tp1Hit && ask <= tp1Level)
      {
         tp1Hit = true;
         double newSL = NormalizeDouble(entryPrice, _Digits);
         if(newSL < currentSL - _Point)
         {
            trade.PositionModify(_Symbol, newSL, tp3Level);
            Print("TP1 hit SELL | SL → entry (", newSL, ") trade is risk-free");
         }
         if(EnablePartials) DoPartialClose(TP1_ClosePct);
      }

      // ── TP2 reached → SL moves to TP1 ──
      if(!tp2Hit && ask <= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL < currentSL - _Point)
         {
            trade.PositionModify(_Symbol, newSL, tp3Level);
            Print("TP2 hit SELL | SL → TP1 (", newSL, ") profit locked");
         }
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
}

//+------------------------------------------------------------------+
//| Partial close helper                                             |
//+------------------------------------------------------------------+
void DoPartialClose(double pct)
{
   if(!EnablePartials) return;
   double volMin = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volStep= SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double lots   = PositionGetDouble(POSITION_VOLUME);
   double toClose= MathFloor(lots * pct / 100.0 / volStep) * volStep;
   if(toClose >= volMin)
      trade.PositionClosePartial(_Symbol, toClose);
}

//+------------------------------------------------------------------+
//| Check if EA-owned position is open                               |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   if(!PositionSelect(_Symbol)) return false;
   return (PositionGetInteger(POSITION_MAGIC) == MagicNumber);
}

//+------------------------------------------------------------------+
//| Force close position                                             |
//+------------------------------------------------------------------+
void ClosePosition(string reason)
{
   if(!HasOpenPosition()) return;
   double profit = PositionGetDouble(POSITION_PROFIT);
   trade.PositionClose(_Symbol);
   Print("Position closed | Reason=", reason, " PnL=$", profit);
}

//+------------------------------------------------------------------+
//| Day filter                                                       |
//+------------------------------------------------------------------+
bool IsTradingDay(int dow)
{
   if(dow == 0 || dow == 6) return false;        // Weekend
   if(dow == 1 && !FilterMonday)    return false;
   if(dow == 2 && !FilterTuesday)   return false;
   if(dow == 3 && !FilterWednesday) return false; // ← OFF by default
   if(dow == 4 && !FilterThursday)  return false;
   if(dow == 5 && !FilterFriday)    return false;
   return true;
}

//+------------------------------------------------------------------+
//| CSV — log entry                                                  |
//+------------------------------------------------------------------+
void LogTradeEntry(string dir, double entry, double sl,
                   double tp1, double tp2, double tp3, double lots)
{
   if(!EnableCSV || csvHandle == INVALID_HANDLE) return;

   datetime utcNow = TimeCurrent() - ServerOffsetHours * 3600;
   MqlDateTime dt;
   TimeToStruct(utcNow, dt);
   string dayNames[] = {"Sun","Mon","Tue","Wed","Thu","Fri","Sat"};

   double atrBuf[];
   ArraySetAsSeries(atrBuf, true);
   double currentATR = 0;
   if(CopyBuffer(atrHandle, 0, 1, 1, atrBuf) > 0) currentATR = atrBuf[0];

   double vpp      = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE) /
                     SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double riskEst  = lots * slDistance * vpp;

   FileWrite(csvHandle,
      TimeToString(utcNow, TIME_DATE),
      dayNames[dt.day_of_week],
      dir,
      DoubleToString(entry,    _Digits),
      DoubleToString(sl,       _Digits),
      DoubleToString(tp1,      _Digits),
      DoubleToString(tp2,      _Digits),
      DoubleToString(tp3,      _Digits),
      DoubleToString(lots,     2),
      DoubleToString(riskEst,  2),
      "", "", "",                        // ExitPrice, ExitReason, PnL — filled by OnTradeTransaction
      DoubleToString(slDistance, 0),
      DoubleToString(currentATR, 4),
      "",                                // ATR baseline (filled later)
      "");                               // HoldTime (filled later)
   FileFlush(csvHandle);
}

//+------------------------------------------------------------------+
//| CSV — update last row with exit data                             |
//+------------------------------------------------------------------+
void UpdateCSVExit(double exitPrice, string exitReason, double pnl)
{
   // Note: updating in-place requires re-reading the file.
   // Simpler approach: append an exit-only row tagged with today's date.
   if(!EnableCSV || csvHandle == INVALID_HANDLE) return;

   datetime utcNow = TimeCurrent() - ServerOffsetHours * 3600;
   FileWrite(csvHandle,
      TimeToString(utcNow, TIME_DATE | TIME_MINUTES),
      "EXIT", exitReason,
      "", "", "", "", "",
      "", "",
      DoubleToString(exitPrice, _Digits),
      exitReason,
      DoubleToString(pnl, 2),
      "", "", "", "");
   FileFlush(csvHandle);
}
