//+------------------------------------------------------------------+
//| Main tick handler                                                |
//+------------------------------------------------------------------+
void OnTick()
{
   datetime serverTime = TimeCurrent();
   datetime utcTime    = serverTime - ServerOffsetHours * 3600;

   MqlDateTime utcDT;
   TimeToStruct(utcTime, utcDT);

   //--- Daily reset at UTC midnight
   if(utcDT.day != lastResetDay)
   {
      lastResetDay      = utcDT.day;
      rangeFormed       = false;
      tradeOpenedToday  = false;
      breakoutPending   = false;
      breakoutDir       = 0;
      rangeHigh         = 0;
      rangeLow          = 0;
      slDistance        = 0;
      cachedLots        = 0;
      beActivated       = false;
      tp2Hit            = false;
      entryPrice        = 0;
      originalSL        = 0;
   }

   //--- Force close at 17:00 UTC
   if(HasOpenPosition())
   {
      if(utcDT.hour > SessionCloseHour ||
         (utcDT.hour == SessionCloseHour && utcDT.min >= SessionCloseMin))
      {
         ClosePosition("SESSION_END");
         return;
      }
      ManagePosition();
      return;
   }

   if(tradeOpenedToday)  return;
   if(!IsTradingDay(utcDT.day_of_week)) return;

   //--- New bar detection
   datetime currentBar = iTime(_Symbol, PERIOD_M5, 0);
   bool     newBar     = (currentBar != lastBarTime);
   if(newBar) lastBarTime = currentBar;

   //--- STEP 1: Calculate range when 14:50 UTC is reached
   if(!rangeFormed)
   {
      int totalMin = utcDT.hour * 60 + utcDT.min;
      if(totalMin >= 14 * 60 + 50)
         TryCalculateRange();
   }
   if(!rangeFormed) return;

   //--- STEP 2: Entry window 14:50 → 14:50+EntryWindowEnd_Min UTC
   int totalMin    = utcDT.hour * 60 + utcDT.min;
   int windowStart = 14 * 60 + 50;
   int windowEnd   = windowStart + EntryWindowEnd_Min;
   if(totalMin < windowStart || totalMin >= windowEnd) return;

   //--- STEP 2A: Detect breakout cross
   if(!breakoutPending)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      if(ask > rangeHigh)
      {
         breakoutPending    = true;
         breakoutDir        = 1;
         breakoutCandleTime = currentBar;
         Print("Breakout UP → ask=", ask, " > rangeHigh=", rangeHigh, " — awaiting confirmation");
      }
      else if(bid < rangeLow)
      {
         breakoutPending    = true;
         breakoutDir        = -1;
         breakoutCandleTime = currentBar;
         Print("Breakout DOWN → bid=", bid, " < rangeLow=", rangeLow, " — awaiting confirmation");
      }
   }

   //--- STEP 2B: Confirm on next bar close
   if(breakoutPending && currentBar != breakoutCandleTime)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      bool confirmed = (breakoutDir == 1 && ask > rangeHigh) ||
                       (breakoutDir == -1 && bid < rangeLow);

      if(confirmed)
         ExecuteTrade(breakoutDir);
      else
      {
         Print("False breakout — price back in range. Skipping.");
         breakoutPending = false;
         breakoutDir     = 0;
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate NY pre-session range: candles 14:35/14:40/14:45 UTC   |
//+------------------------------------------------------------------+
void TryCalculateRange()
{
   datetime serverNow = TimeCurrent();
   MqlDateTime srvDT;
   TimeToStruct(serverNow, srvDT);

   // Midnight of current server day
   datetime srvMidnight = StringToTime(
      StringFormat("%04d.%02d.%02d 00:00:00", srvDT.year, srvDT.mon, srvDT.day));

   // Server timestamps for the 3 range candles
   // Server time = UTC + ServerOffsetHours, so:
   // 14:35 UTC → (14 + offset):35 server time
   datetime c1_srv = srvMidnight + (14 + ServerOffsetHours) * 3600 + 35 * 60;
   datetime c2_srv = srvMidnight + (14 + ServerOffsetHours) * 3600 + 40 * 60;
   datetime c3_srv = srvMidnight + (14 + ServerOffsetHours) * 3600 + 45 * 60;

   int i1 = iBarShift(_Symbol, PERIOD_M5, c1_srv, false);
   int i2 = iBarShift(_Symbol, PERIOD_M5, c2_srv, false);
   int i3 = iBarShift(_Symbol, PERIOD_M5, c3_srv, false);

   if(i1 < 0 || i2 < 0 || i3 < 0)
   { Print("Range candles not found. Check ServerOffsetHours=", ServerOffsetHours); return; }

   // Verify timestamps (within 1 bar = 300s tolerance)
   if(MathAbs((int)(iTime(_Symbol,PERIOD_M5,i1)-c1_srv)) > 300 ||
      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i2)-c2_srv)) > 300 ||
      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i3)-c3_srv)) > 300)
   { Print("Range candle time mismatch. Verify ServerOffsetHours."); return; }

   // Full range of all 3 candles (NOT average, NOT 2 candles)
   rangeHigh = MathMax(iHigh(_Symbol,PERIOD_M5,i1),
               MathMax(iHigh(_Symbol,PERIOD_M5,i2), iHigh(_Symbol,PERIOD_M5,i3)));
   rangeLow  = MathMin(iLow(_Symbol, PERIOD_M5,i1),
               MathMin(iLow(_Symbol, PERIOD_M5,i2), iLow(_Symbol, PERIOD_M5,i3)));
   slDistance = (rangeHigh - rangeLow) / _Point;

   Print("Range: H=", rangeHigh, " L=", rangeLow, " SL_dist=", slDistance, " pts");

   //--- Range filter
   if(slDistance < MinSL_Points)
   { Print("SKIP: Range ", slDistance, " < MinSL ", MinSL_Points); return; }
   if(slDistance > MaxSL_Points)
   { Print("SKIP: Range ", slDistance, " > MaxSL ", MaxSL_Points); return; }

   //--- ATR filter
   if(ATR_FilterEnable && !CheckATRFilter()) return;

   //--- Calculate lots once (cached until next daily reset)
   cachedLots = CalculateLotSize(slDistance);
   if(cachedLots <= 0) { Print("SKIP: Lot calculation failed"); return; }

   rangeFormed = true;
   double vpp = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE) /
                SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   Print("Range valid | lots=", cachedLots,
         " est_risk=$", NormalizeDouble(cachedLots * slDistance * vpp, 2));
}

//+------------------------------------------------------------------+
//| ATR filter                                                       |
//+------------------------------------------------------------------+
bool CheckATRFilter()
{
   double curBuf[];
   ArraySetAsSeries(curBuf, true);
   if(CopyBuffer(atrHandle, 0, 1, 1, curBuf) <= 0) return true;
   double currentATR = curBuf[0];

   // Baseline: average ATR over last ATR_BaselineDays × 78 M5 bars
   int    barsNeeded = ATR_BaselineDays * 78;
   double baseBuf[];
   ArraySetAsSeries(baseBuf, true);
   int copied = CopyBuffer(atrHandle, 0, 1, barsNeeded, baseBuf);
   if(copied < 10) return true;

   double sum = 0;
   for(int i = 0; i < copied; i++) sum += baseBuf[i];
   double baseline = sum / copied;

   Print("ATR: current=", currentATR,
         " baseline=", baseline,
         " range=[", NormalizeDouble(baseline*ATR_MinMultiplier,4),
         ",", NormalizeDouble(baseline*ATR_MaxMultiplier,4), "]");

   if(currentATR < baseline * ATR_MinMultiplier)
   { Print("ATR too low — skip"); return false; }
   if(currentATR > baseline * ATR_MaxMultiplier)
   { Print("ATR too high — skip"); return false; }
   return true;
}

//+------------------------------------------------------------------+
//| Lot size calculation — v3 uses MathRound (vs MathFloor in v1/v2) |
//|                                                                  |
//| v1/v2 bug: MathFloor(0.0170/0.01)*0.01 = 0.01 (OK at $100k)    |
//|            MathFloor(0.0085/0.01)*0.01 = 0.00 → clamped (WRONG)|
//|                                                                  |
//| v3 fix:    MathRound(0.0170/0.01)*0.01 = 0.02 (closer to target)|
//|            MathRound(0.0085/0.01)*0.01 = 0.01 (correct minimum) |
//|                                                                  |
//| With $100k + 1%: lotsRaw always >= 0.01, so floor=round=same.   |
//| The MathRound ensures correct behavior if account size changes.  |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPts)
{
   double tickVal = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSz  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double volMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double volStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   if(tickSz <= 0 || tickVal <= 0) { Print("ERROR: Invalid tick specs"); return 0; }

   double vpp      = tickVal / tickSz;          // USD per _Point per lot
   double lotsRaw  = RiskAmountUSD / (slPts * vpp);

   // MathRound gives the nearest valid step (handles both over and under)
   double lots = MathRound(lotsRaw / volStep) * volStep;
   lots = MathMax(lots, volMin);
   lots = MathMin(lots, volMax);

   double actualRisk = lots * slPts * vpp;
   Print("Lots: raw=", NormalizeDouble(lotsRaw,4),
         " rounded=", lots,
         " actualRisk=$", NormalizeDouble(actualRisk,2));

   //--- Margin check (must not exceed 90% of free margin)
   double marginReq = 0;
   if(!OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots,
                       SymbolInfoDouble(_Symbol, SYMBOL_ASK), marginReq))
   { Print("ERROR: OrderCalcMargin failed"); return 0; }

   double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
   if(marginReq > freeMargin * 0.90)
   { Print("ERROR: Insufficient margin. Need=", marginReq, " Free=", freeMargin); return 0; }

   return lots;
}

//+------------------------------------------------------------------+
//| Execute trade entry                                              |
//+------------------------------------------------------------------+
void ExecuteTrade(int direction)
{
   if(cachedLots <= 0) return;

   double ask   = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid   = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slDst = slDistance * _Point;

   if(direction == 1) // BUY
   {
      entryPrice = ask;
      originalSL = NormalizeDouble(entryPrice - slDst,            _Digits);
      beLevel    = NormalizeDouble(entryPrice + slDst * (BE_BufferPct/100.0), _Digits);
      tp1Level   = NormalizeDouble(entryPrice + slDst * TP1_RR,   _Digits);
      tp2Level   = NormalizeDouble(entryPrice + slDst * TP2_RR,   _Digits);
      tp3Level   = NormalizeDouble(entryPrice + slDst * TP3_RR,   _Digits);

      if(trade.Buy(cachedLots, _Symbol, ask, originalSL, tp3Level, "BreakoutNY_BUY"))
      {
         tradeOpenedToday = true;
         breakoutPending  = false;
         beActivated      = false;
         tp2Hit           = false;
         Print("BUY | entry=", entryPrice,
               " SL=", originalSL,
               " BE@", beLevel,
               " TP1=", tp1Level,
               " TP2=", tp2Level,
               " TP3=", tp3Level,
               " lots=", cachedLots);
         LogEntry("BUY");
      }
   }
   else // SELL
   {
      entryPrice = bid;
      originalSL = NormalizeDouble(entryPrice + slDst,            _Digits);
      beLevel    = NormalizeDouble(entryPrice - slDst * (BE_BufferPct/100.0), _Digits);
      tp1Level   = NormalizeDouble(entryPrice - slDst * TP1_RR,   _Digits);
      tp2Level   = NormalizeDouble(entryPrice - slDst * TP2_RR,   _Digits);
      tp3Level   = NormalizeDouble(entryPrice - slDst * TP3_RR,   _Digits);

      if(trade.Sell(cachedLots, _Symbol, bid, originalSL, tp3Level, "BreakoutNY_SELL"))
      {
         tradeOpenedToday = true;
         breakoutPending  = false;
         beActivated      = false;
         tp2Hit           = false;
         Print("SELL | entry=", entryPrice,
               " SL=", originalSL,
               " BE@", beLevel,
               " TP1=", tp1Level,
               " TP2=", tp2Level,
               " TP3=", tp3Level,
               " lots=", cachedLots);
         LogEntry("SELL");
      }
   }
}

//+------------------------------------------------------------------+
//| ManagePosition — v3 BE logic                                     |
//|                                                                  |
//| BUY flow:                                                        |
//|   price >= beLevel  → SL moves to entryPrice (BE activated)     |
//|   price >= tp2Level → SL moves to tp1Level (profit locked)      |
//|   price >= tp3Level → closed by hard TP                         |
//|                                                                  |
//| The BE check runs EVERY tick until activated. Once activated,    |
//| it won't fire again (beActivated=true). Same for tp2Hit.         |
//|                                                                  |
//| Key difference from v1: BE fires at 50% of SL distance,         |
//| not at 20% (too early). The SL moves to EXACTLY entryPrice,      |
//| not to entryPrice + small buffer (which was confusing).          |
//+------------------------------------------------------------------+
void ManagePosition()
{
   if(!HasOpenPosition()) return;

   double currentSL = PositionGetDouble(POSITION_SL);
   long   posType   = PositionGetInteger(POSITION_TYPE);

   if(posType == POSITION_TYPE_BUY)
   {
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      // Stage 1 → 2: BE activation (50% of SL distance)
      if(!beActivated && bid >= beLevel)
      {
         beActivated = true;
         double newSL = NormalizeDouble(entryPrice, _Digits);
         if(newSL > currentSL + _Point) // Only move if it's actually better
         {
            if(trade.PositionModify(_Symbol, newSL, tp3Level))
               Print("BE activated BUY | price=", bid, " → SL to entry=", newSL);
         }
      }

      // Stage 2 → 3: TP2 hit → SL to TP1
      if(!tp2Hit && bid >= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL > currentSL + _Point)
         {
            if(trade.PositionModify(_Symbol, newSL, tp3Level))
               Print("TP2 hit BUY | SL → TP1=", newSL, " (profit locked)");
         }
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
   else if(posType == POSITION_TYPE_SELL)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

      // Stage 1 → 2: BE activation
      if(!beActivated && ask <= beLevel)
      {
         beActivated = true;
         double newSL = NormalizeDouble(entryPrice, _Digits);
         if(newSL < currentSL - _Point)
         {
            if(trade.PositionModify(_Symbol, newSL, tp3Level))
               Print("BE activated SELL | price=", ask, " → SL to entry=", newSL);
         }
      }

      // Stage 2 → 3: TP2 hit → SL to TP1
      if(!tp2Hit && ask <= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL < currentSL - _Point)
         {
            if(trade.PositionModify(_Symbol, newSL, tp3Level))
               Print("TP2 hit SELL | SL → TP1=", newSL, " (profit locked)");
         }
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
}

//+------------------------------------------------------------------+
//| Partial close helper                                             |
//+------------------------------------------------------------------+
void DoPartialClose(double pct)
{
   double volMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double current = PositionGetDouble(POSITION_VOLUME);
   double toClose = MathFloor(current * pct / 100.0 / volStep) * volStep;
   if(toClose >= volMin)
      trade.PositionClosePartial(_Symbol, toClose);
}

//+------------------------------------------------------------------+
//| Check if EA-owned position is open on this symbol               |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   if(!PositionSelect(_Symbol)) return false;
   return (PositionGetInteger(POSITION_MAGIC) == MagicNumber);
}

//+------------------------------------------------------------------+
//| Force close                                                      |
//+------------------------------------------------------------------+
void ClosePosition(string reason)
{
   if(!HasOpenPosition()) return;
   double pnl = PositionGetDouble(POSITION_PROFIT);
   if(trade.PositionClose(_Symbol))
      Print("Closed | reason=", reason, " pnl=$", NormalizeDouble(pnl,2));
}

//+------------------------------------------------------------------+
//| Day of week filter                                               |
//+------------------------------------------------------------------+
bool IsTradingDay(int dow)
{
   if(dow == 0 || dow == 6) return false;
   if(dow == 1 && !FilterMonday)    return false;
   if(dow == 2 && !FilterTuesday)   return false;
   if(dow == 3 && !FilterWednesday) return false; // OFF by default
   if(dow == 4 && !FilterThursday)  return false;
   if(dow == 5 && !FilterFriday)    return false;
   return true;
}

//+------------------------------------------------------------------+
//| CSV logging                                                      |
//+------------------------------------------------------------------+
void LogEntry(string dir)
{
   if(!EnableCSV || csvHandle == INVALID_HANDLE) return;

   datetime utcNow = TimeCurrent() - ServerOffsetHours * 3600;
   MqlDateTime dt;
   TimeToStruct(utcNow, dt);
   string dayNames[] = {"Sun","Mon","Tue","Wed","Thu","Fri","Sat"};

   double atrBuf[];
   ArraySetAsSeries(atrBuf, true);
   double currentATR = 0;
   if(CopyBuffer(atrHandle, 0, 1, 1, atrBuf) > 0) currentATR = atrBuf[0];

   double vpp     = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE) /
                    SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double riskEst = cachedLots * slDistance * vpp;

   FileWrite(csvHandle,
      TimeToString(utcNow, TIME_DATE),
      dayNames[dt.day_of_week],
      dir,
      DoubleToString(cachedLots,  2),
      DoubleToString(riskEst,     2),
      DoubleToString(entryPrice,  _Digits),
      DoubleToString(originalSL,  _Digits),
      DoubleToString(beLevel,     _Digits),
      DoubleToString(tp1Level,    _Digits),
      DoubleToString(tp2Level,    _Digits),
      DoubleToString(tp3Level,    _Digits),
      DoubleToString(slDistance,  0),
      DoubleToString(currentATR,  4));
   FileFlush(csvHandle);
}
//+------------------------------------------------------------------+

