//+------------------------------------------------------------------+
//|  BreakoutNY_RiskDiagnostic.mq5                                   |
//|  Script de diagnóstico COMPLETO de gestión de riesgo             |
//|                                                                  |
//|  PROPÓSITO:                                                      |
//|  Descubrir cómo MT5 calcula realmente el P&L del DJI30           |
//|  cuando TickSize=0 y TickValue=0 (caso CFD sin tick estándar)    |
//|                                                                  |
//|  INSTRUCCIONES:                                                  |
//|  1. Copiar a MQL5/Scripts/                                       |
//|  2. Compilar (F7)                                                |
//|  3. Arrastrar sobre gráfico DJI30 M5 con mercado ABIERTO        |
//|  4. Copiar TODO el output del Journal (clic derecho → Copiar)   |
//|  5. Enviar el texto completo                                     |
//+------------------------------------------------------------------+
#property script_show_inputs

input double RiskUSD   = 1000.0; // Riesgo objetivo por operación (USD)
input int    ServerOff = 2;      // UTC offset del servidor

void OnStart()
{
   string s = _Symbol;

   Print("============================================================");
   Print("  RISK DIAGNOSTIC — ", s, " — ", TimeToString(TimeCurrent()));
   Print("============================================================");

   //--- Bloque 1: Specs crudas de MT5
   double tickSz  = SymbolInfoDouble(s, SYMBOL_TRADE_TICK_SIZE);
   double tickVal = SymbolInfoDouble(s, SYMBOL_TRADE_TICK_VALUE);
   double cs      = SymbolInfoDouble(s, SYMBOL_TRADE_CONTRACT_SIZE);
   double pt      = SymbolInfoDouble(s, SYMBOL_POINT);
   int    digs    = (int)SymbolInfoInteger(s, SYMBOL_DIGITS);
   double volMin  = SymbolInfoDouble(s, SYMBOL_VOLUME_MIN);
   double volMax  = SymbolInfoDouble(s, SYMBOL_VOLUME_MAX);
   double volStep = SymbolInfoDouble(s, SYMBOL_VOLUME_STEP);
   double bid     = SymbolInfoDouble(s, SYMBOL_BID);
   double ask     = SymbolInfoDouble(s, SYMBOL_ASK);
   string calcMode= "";

   ENUM_SYMBOL_CALC_MODE mode =
      (ENUM_SYMBOL_CALC_MODE)SymbolInfoInteger(s, SYMBOL_TRADE_CALC_MODE);
   switch(mode)
   {
      case SYMBOL_CALC_MODE_FOREX:      calcMode = "FOREX";       break;
      case SYMBOL_CALC_MODE_CFD:        calcMode = "CFD";         break;
      case SYMBOL_CALC_MODE_FUTURES:    calcMode = "FUTURES";     break;
      case SYMBOL_CALC_MODE_CFDINDEX:   calcMode = "CFD_INDEX";   break;
      case SYMBOL_CALC_MODE_CFDLEVERAGE:calcMode = "CFD_LEVERAGE";break;
      default: calcMode = "OTHER(" + IntegerToString((int)mode) + ")";
   }

   Print("--- [1] RAW SPECS FROM MT5 ---");
   PrintFormat("  CalcMode      : %s  (enum=%d)", calcMode, (int)mode);
   PrintFormat("  Digits        : %d",   digs);
   PrintFormat("  ContractSize  : %.6f", cs);
   PrintFormat("  TickSize      : %.8f", tickSz);
   PrintFormat("  TickValue     : %.8f", tickVal);
   PrintFormat("  Point(_Point) : %.8f", pt);
   PrintFormat("  VolumeMin     : %.4f", volMin);
   PrintFormat("  VolumeMax     : %.4f", volMax);
   PrintFormat("  VolumeStep    : %.4f", volStep);
   PrintFormat("  Bid           : %.2f", bid);
   PrintFormat("  Ask           : %.2f", ask);
   PrintFormat("  Spread        : %.1f pts", (ask-bid)/pt);

   //--- Bloque 2: Diagnóstico de la fórmula estándar
   Print("\n--- [2] STANDARD FORMULA DIAGNOSIS ---");
   if(tickSz <= 0 || tickVal <= 0)
   {
      Print("  *** WARNING: TickSize=0 or TickValue=0 ***");
      Print("  Standard formula ValuePerPoint=TickValue/TickSize FAILS");
      Print("  This means dynamic lot sizing is BROKEN in current EA code");
      Print("  Root cause: broker does not publish tick data for this CFD");
   }
   else
   {
      double vpp = tickVal / tickSz;
      PrintFormat("  ValuePerPoint = %.6f / %.6f = %.6f USD/pt/lot", tickVal, tickSz, vpp);
   }

   //--- Bloque 3: Fórmula CFD_INDEX correcta
   // Para CFD de índice sin tick data, el P&L se calcula así:
   // PnL = (PriceClose - PriceOpen) × ContractSize × Lots
   // ValuePerPoint = ContractSize × Point
   // Porque: moverse 1 _Point en precio con 1 lote = ContractSize × _Point USD
   Print("\n--- [3] CFD_INDEX CORRECT FORMULA ---");
   double vppCFD = cs * pt;
   PrintFormat("  Formula: ValuePerPoint = ContractSize × Point");
   PrintFormat("           = %.4f × %.8f = %.8f USD/pt/lot", cs, pt, vppCFD);
   PrintFormat("  Meaning: 1 _Point move with 1 lot = $%.8f", vppCFD);
   PrintFormat("  Meaning: 100 pts move with 0.01 lots = $%.6f", 100.0 * vppCFD * 0.01);

   //--- Bloque 4: OrderCalcProfit — verdad absoluta de MT5
   // MT5 calcula el P&L real con esta función — usarla como fuente de verdad
   Print("\n--- [4] OrderCalcProfit GROUND TRUTH ---");
   double profitBuy = 0, profitSell = 0;
   double testOpenPrice = ask;
   double testLots      = 1.0;  // siempre 1 lote para medir
   double testMovePts   = 100.0; // mover 100 _Points

   double closeUp   = testOpenPrice + testMovePts * pt;
   double closeDown = testOpenPrice - testMovePts * pt;

   if(OrderCalcProfit(ORDER_TYPE_BUY,  s, testLots, testOpenPrice, closeUp,   profitBuy))
      PrintFormat("  BUY  1lot: open=%.2f close=%.2f (+100pts) → profit=$%.4f",
                  testOpenPrice, closeUp, profitBuy);
   else
      Print("  BUY OrderCalcProfit FAILED");

   if(OrderCalcProfit(ORDER_TYPE_SELL, s, testLots, testOpenPrice, closeDown, profitSell))
      PrintFormat("  SELL 1lot: open=%.2f close=%.2f (-100pts) → profit=$%.4f",
                  testOpenPrice, closeDown, profitSell);
   else
      Print("  SELL OrderCalcProfit FAILED");

   // Derivar ValuePerPoint desde la verdad de MT5
   double vppFromCalc = 0;
   if(profitBuy != 0)
   {
      vppFromCalc = profitBuy / testMovePts / testLots;
      PrintFormat("  => TRUE ValuePerPoint = $%.4f / 100pts / 1lot = $%.6f per _Point per lot",
                  profitBuy, vppFromCalc);
   }

   //--- Bloque 5: Cálculo de lotes CORRECTO para distintos SL
   Print("\n--- [5] CORRECT LOT CALCULATION (using OrderCalcProfit truth) ---");
   if(vppFromCalc > 0)
   {
      double testSLs[] = {8000, 9750, 11750, 14000, 16260, 20000};
      PrintFormat("  Risk target: $%.2f", RiskUSD);
      PrintFormat("  %-12s %-12s %-12s %-15s %-12s",
                  "SL_pts", "lotsRaw", "lotsFinal", "ActualRisk", "% of 100k");
      for(int i = 0; i < ArraySize(testSLs); i++)
      {
         double sl      = testSLs[i];
         double slUSD   = sl * vppFromCalc;  // $ cost of this SL per lot
         double lotsRaw = RiskUSD / slUSD;
         double lotsR   = MathRound(lotsRaw / volStep) * volStep;
         double lotsF   = MathMax(MathMin(lotsR, volMax), volMin);
         double actual  = lotsF * slUSD;
         PrintFormat("  %-12.0f %-12.6f %-12.2f $%-14.2f %.2f%%",
                     sl, lotsRaw, lotsF, actual, actual/100000.0*100.0);
      }
   }
   else
   {
      Print("  Cannot calculate — OrderCalcProfit returned 0");
   }

   //--- Bloque 6: OrderCalcMargin — cuánto margen usa 0.01 lotes
   Print("\n--- [6] MARGIN REQUIREMENTS ---");
   double marginBuy = 0, marginSell = 0;
   double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   if(OrderCalcMargin(ORDER_TYPE_BUY,  s, 0.01, ask, marginBuy))
      PrintFormat("  BUY  0.01 lots → margin required: $%.2f", marginBuy);
   if(OrderCalcMargin(ORDER_TYPE_SELL, s, 0.01, bid, marginSell))
      PrintFormat("  SELL 0.01 lots → margin required: $%.2f", marginSell);
   PrintFormat("  Account balance    : $%.2f", balance);
   PrintFormat("  Account free margin: $%.2f", freeMargin);

   //--- Bloque 7: Comparar las dos fórmulas
   Print("\n--- [7] FORMULA COMPARISON ---");
   PrintFormat("  Formula A (TickValue/TickSize): %.8f  [BROKEN if TickSz=0]",
               tickSz > 0 ? tickVal/tickSz : 0.0);
   PrintFormat("  Formula B (ContractSize×Point): %.8f", vppCFD);
   PrintFormat("  Formula C (OrderCalcProfit):    %.8f  [GROUND TRUTH]", vppFromCalc);

   if(vppFromCalc > 0)
   {
      double errB = MathAbs(vppCFD - vppFromCalc) / vppFromCalc * 100.0;
      PrintFormat("  Error of Formula B vs C: %.2f%%", errB);
      if(errB < 1.0)
         Print("  => Formula B (ContractSize*Point) is CORRECT for this instrument");
      else
         Print("  => Use Formula C (OrderCalcProfit) for accurate sizing");
   }

   //--- Bloque 8: SL en puntos del rango de HOY (si es posible)
   Print("\n--- [8] TODAY'S RANGE (pre-NY candles if available) ---");
   datetime serverNow = TimeCurrent();
   MqlDateTime srvDT;
   TimeToStruct(serverNow, srvDT);
   datetime srvMid = StringToTime(
      StringFormat("%04d.%02d.%02d 00:00:00", srvDT.year, srvDT.mon, srvDT.day));

   datetime c1 = srvMid + (14+ServerOff)*3600 + 35*60;
   datetime c2 = srvMid + (14+ServerOff)*3600 + 40*60;
   datetime c3 = srvMid + (14+ServerOff)*3600 + 45*60;

   int i1 = iBarShift(s, PERIOD_M5, c1, false);
   int i2 = iBarShift(s, PERIOD_M5, c2, false);
   int i3 = iBarShift(s, PERIOD_M5, c3, false);

   if(i1 >= 0 && i2 >= 0 && i3 >= 0)
   {
      double rH = MathMax(iHigh(s,PERIOD_M5,i1), MathMax(iHigh(s,PERIOD_M5,i2), iHigh(s,PERIOD_M5,i3)));
      double rL = MathMin(iLow(s, PERIOD_M5,i1), MathMin(iLow(s, PERIOD_M5,i2), iLow(s, PERIOD_M5,i3)));
      double rangePts = (rH - rL) / pt;
      PrintFormat("  Range candles found: H=%.2f L=%.2f SL=%.0f pts", rH, rL, rangePts);
      if(vppFromCalc > 0)
      {
         double riskAtRange = rangePts * vppFromCalc;
         double lotsForRange = MathRound((RiskUSD/riskAtRange)/volStep)*volStep;
         lotsForRange = MathMax(MathMin(lotsForRange, volMax), volMin);
         PrintFormat("  SL=%.0f pts → $%.2f/lot → lots for $%.0f risk = %.2f → actual risk=$%.2f",
                     rangePts, riskAtRange, RiskUSD, lotsForRange,
                     lotsForRange*riskAtRange);
      }
   }
   else
      Print("  Range candles not found (run after 14:50 UTC or check ServerOffsetHours)");

   Print("\n============================================================");
   Print("  DIAGNOSTIC COMPLETE — Copy all output and send");
   Print("============================================================");
}
//+------------------------------------------------------------------+

