//+------------------------------------------------------------------+
double GetValuePerPoint()
{
   // Primary formula: ContractSize × Point
   // Confirmed correct for DJI30 FundingPips by diagnostic script
   double cs  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   double pt  = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double vpp = cs * pt;

   if(vpp > 0)
   {
      // Cross-check with OrderCalcProfit for verification
      double profitCheck = 0;
      double curAsk = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double closeUp = curAsk + 100.0 * pt;
      if(OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0, curAsk, closeUp, profitCheck)
         && profitCheck > 0)
      {
         double vppCheck = profitCheck / 100.0; // profit for 100pts, 1 lot
         double err = MathAbs(vpp - vppCheck) / vppCheck * 100.0;
         PrintFormat("VPP verification: Formula=%f  OrderCalcProfit=%f  Error=%.2f%%",
                     vpp, vppCheck, err);
         if(err > 5.0)
         {
            Print("WARNING: Formula mismatch >5% — using OrderCalcProfit value");
            vpp = vppCheck;
         }
      }
      return vpp;
   }

   // Fallback: derive from OrderCalcProfit directly
   Print("WARNING: ContractSize*Point=0 — falling back to OrderCalcProfit");
   double profit = 0;
   double curAsk = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   if(OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0, curAsk,
                      curAsk + 100.0 * pt, profit) && profit > 0)
      return profit / 100.0;

   Print("ERROR: Cannot determine ValuePerPoint");
   return 0;
}

