//+------------------------------------------------------------------+
void OnTick()
{
   datetime serverTime = TimeCurrent();
   datetime utcTime    = serverTime - ServerOffsetHours * 3600;
   MqlDateTime utcDT;
   TimeToStruct(utcTime, utcDT);

   //--- Daily reset
   if(utcDT.day != lastResetDay)
   {
      lastResetDay      = utcDT.day;
      rangeFormed       = false;
      tradeOpenedToday  = false;
      breakoutPending   = false;
      breakoutDir       = 0;
      rangeHigh = rangeLow = slDistance = cachedLots = 0;
      beActivated = tp2Hit = false;
      entryPrice = originalSL = 0;
   }

   //--- Force close at session end
   if(HasOpenPosition())
   {
      if(utcDT.hour > SessionCloseHour ||
         (utcDT.hour == SessionCloseHour && utcDT.min >= SessionCloseMin))
      { ClosePosition("SESSION_END"); return; }
      ManagePosition();
      return;
   }

   if(tradeOpenedToday) return;
   if(!IsTradingDay(utcDT.day_of_week)) return;

   datetime curBar = iTime(_Symbol, PERIOD_M5, 0);
   bool newBar     = (curBar != lastBarTime);
   if(newBar) lastBarTime = curBar;

   //--- Calculate range at 14:50 UTC
   if(!rangeFormed)
   {
      int totalMin = utcDT.hour * 60 + utcDT.min;
      if(totalMin >= 14 * 60 + 50)
         TryCalculateRange();
   }
   if(!rangeFormed) return;

   //--- Entry window
   int totalMin = utcDT.hour * 60 + utcDT.min;
   int wStart   = 14 * 60 + 50;
   int wEnd     = wStart + EntryWindowEnd_Min;
   if(totalMin < wStart || totalMin >= wEnd) return;

   //--- Detect breakout
   if(!breakoutPending)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      if(ask > rangeHigh)
      { breakoutPending=true; breakoutDir=1;  breakoutBarTime=curBar;
        Print("Breakout UP → ask=",ask," > rangeHigh=",rangeHigh); }
      else if(bid < rangeLow)
      { breakoutPending=true; breakoutDir=-1; breakoutBarTime=curBar;
        Print("Breakout DOWN → bid=",bid," < rangeLow=",rangeLow); }
   }

   //--- Confirm on next bar
   if(breakoutPending && curBar != breakoutBarTime)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      bool confirmed = (breakoutDir==1 && ask>rangeHigh) ||
                       (breakoutDir==-1 && bid<rangeLow);
      if(confirmed) ExecuteTrade(breakoutDir);
      else
      { Print("False breakout — price back in range");
        breakoutPending=false; breakoutDir=0; }
   }
}

//+------------------------------------------------------------------+
//| Calculate pre-NY range: candles 14:35/14:40/14:45 UTC           |
//+------------------------------------------------------------------+
void TryCalculateRange()
{
   datetime serverNow = TimeCurrent();
   MqlDateTime srvDT;
   TimeToStruct(serverNow, srvDT);
   datetime srvMid = StringToTime(
      StringFormat("%04d.%02d.%02d 00:00:00", srvDT.year, srvDT.mon, srvDT.day));

   datetime c1 = srvMid + (14+ServerOffsetHours)*3600 + 35*60;
   datetime c2 = srvMid + (14+ServerOffsetHours)*3600 + 40*60;
   datetime c3 = srvMid + (14+ServerOffsetHours)*3600 + 45*60;

   int i1=iBarShift(_Symbol,PERIOD_M5,c1,false);
   int i2=iBarShift(_Symbol,PERIOD_M5,c2,false);
   int i3=iBarShift(_Symbol,PERIOD_M5,c3,false);
   if(i1<0||i2<0||i3<0) { Print("Range candles not found"); return; }

   if(MathAbs((int)(iTime(_Symbol,PERIOD_M5,i1)-c1))>300 ||
      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i2)-c2))>300 ||
      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i3)-c3))>300)
   { Print("Range candle mismatch — check ServerOffsetHours"); return; }

   rangeHigh = MathMax(iHigh(_Symbol,PERIOD_M5,i1),
               MathMax(iHigh(_Symbol,PERIOD_M5,i2),iHigh(_Symbol,PERIOD_M5,i3)));
   rangeLow  = MathMin(iLow(_Symbol, PERIOD_M5,i1),
               MathMin(iLow(_Symbol, PERIOD_M5,i2),iLow(_Symbol, PERIOD_M5,i3)));
   slDistance = (rangeHigh - rangeLow) / _Point;

   Print("Range: H=",rangeHigh," L=",rangeLow," SL_dist=",slDistance," pts");

   if(slDistance < MinSL_Points)
   { Print("SKIP: Range ",slDistance," < MinSL ",MinSL_Points); return; }
   if(slDistance > MaxSL_Points)
   { Print("SKIP: Range ",slDistance," > MaxSL ",MaxSL_Points); return; }

   if(ATR_FilterEnable && !CheckATRFilter()) return;

   cachedLots = CalculateLotSize(slDistance);
   if(cachedLots <= 0) { Print("SKIP: Lot calculation failed"); return; }

   rangeFormed = true;
   PrintFormat("Range valid | lots=%.2f | risk=$%.2f (%.3f%% of $100k)",
               cachedLots, cachedLots*slDistance*cachedVPP,
               cachedLots*slDistance*cachedVPP/100000.0*100.0);
}

//+------------------------------------------------------------------+
//| ATR filter                                                       |
//+------------------------------------------------------------------+
bool CheckATRFilter()
{
   double cur[];
   ArraySetAsSeries(cur, true);
   if(CopyBuffer(atrHandle, 0, 1, 1, cur) <= 0) return true;
   double currentATR = cur[0];

   double base[];
   ArraySetAsSeries(base, true);
   int copied = CopyBuffer(atrHandle, 0, 1, ATR_BaselineDays*78, base);
   if(copied < 10) return true;

   double sum = 0;
   for(int i = 0; i < copied; i++) sum += base[i];
   double baseline = sum / copied;

   PrintFormat("ATR: current=%.4f baseline=%.4f min=%.4f max=%.4f",
               currentATR, baseline,
               baseline*ATR_MinMultiplier, baseline*ATR_MaxMultiplier);

   if(currentATR < baseline*ATR_MinMultiplier) { Print("ATR too low"); return false; }
   if(currentATR > baseline*ATR_MaxMultiplier) { Print("ATR too high"); return false; }
   return true;
}

//+------------------------------------------------------------------+
//| Lot size calculation — CORRECTED ValuePerPoint                   |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPts)
{
   //--- THE KEY FIX: use cachedVPP (ContractSize × Point = $0.05)
   //    NOT TickValue/TickSize which returns 0/0 for DJI30
   double vpp     = cachedVPP;
   double volMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double volStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   if(vpp <= 0) { Print("ERROR: VPP=0 — cannot size position"); return 0; }

   double lotsRaw = RiskAmountUSD / (slPts * vpp);
   double lots    = MathRound(lotsRaw / volStep) * volStep;
   lots           = MathMax(MathMin(lots, volMax), volMin);

   double actualRisk = lots * slPts * vpp;
   PrintFormat("Lots: raw=%.4f → %.2f | risk=$%.2f (%.3f%%)",
               lotsRaw, lots, actualRisk, actualRisk/100000.0*100.0);

   //--- Margin check
   double marginReq = 0;
   if(!OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots,
                       SymbolInfoDouble(_Symbol, SYMBOL_ASK), marginReq))
   { Print("ERROR: OrderCalcMargin failed"); return 0; }
   if(marginReq > AccountInfoDouble(ACCOUNT_MARGIN_FREE) * 0.90)
   { Print("ERROR: Insufficient margin"); return 0; }

   return lots;
}

//+------------------------------------------------------------------+
//| Execute trade                                                    |
//+------------------------------------------------------------------+
void ExecuteTrade(int direction)
{
   if(cachedLots <= 0) return;

   double ask  = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid  = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slD  = slDistance * _Point;

   if(direction == 1) // BUY
   {
      entryPrice = ask;
      originalSL = NormalizeDouble(entryPrice - slD,                  _Digits);
      beLevel    = NormalizeDouble(entryPrice + slD*(BE_BufferPct/100.0), _Digits);
      tp1Level   = NormalizeDouble(entryPrice + slD*TP1_RR,           _Digits);
      tp2Level   = NormalizeDouble(entryPrice + slD*TP2_RR,           _Digits);
      tp3Level   = NormalizeDouble(entryPrice + slD*TP3_RR,           _Digits);

      if(trade.Buy(cachedLots, _Symbol, ask, originalSL, tp3Level, "BreakoutNY_BUY"))
      {
         tradeOpenedToday=true; breakoutPending=false;
         beActivated=false; tp2Hit=false;
         PrintFormat("BUY | entry=%.2f SL=%.2f BE@%.2f TP1=%.2f TP2=%.2f TP3=%.2f lots=%.2f",
                     entryPrice, originalSL, beLevel, tp1Level, tp2Level, tp3Level, cachedLots);
         LogEntry("BUY");
      }
   }
   else // SELL
   {
      entryPrice = bid;
      originalSL = NormalizeDouble(entryPrice + slD,                  _Digits);
      beLevel    = NormalizeDouble(entryPrice - slD*(BE_BufferPct/100.0), _Digits);
      tp1Level   = NormalizeDouble(entryPrice - slD*TP1_RR,           _Digits);
      tp2Level   = NormalizeDouble(entryPrice - slD*TP2_RR,           _Digits);
      tp3Level   = NormalizeDouble(entryPrice - slD*TP3_RR,           _Digits);

      if(trade.Sell(cachedLots, _Symbol, bid, originalSL, tp3Level, "BreakoutNY_SELL"))
      {
         tradeOpenedToday=true; breakoutPending=false;
         beActivated=false; tp2Hit=false;
         PrintFormat("SELL | entry=%.2f SL=%.2f BE@%.2f TP1=%.2f TP2=%.2f TP3=%.2f lots=%.2f",
                     entryPrice, originalSL, beLevel, tp1Level, tp2Level, tp3Level, cachedLots);
         LogEntry("SELL");
      }
   }
}

//+------------------------------------------------------------------+
//| ManagePosition — BE=50% + TP2 trailing                          |
//+------------------------------------------------------------------+
void ManagePosition()
{
   if(!HasOpenPosition()) return;
   double curSL  = PositionGetDouble(POSITION_SL);
   long   posTyp = PositionGetInteger(POSITION_TYPE);

   if(posTyp == POSITION_TYPE_BUY)
   {
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      if(!beActivated && bid >= beLevel)
      {
         beActivated = true;
         double newSL = NormalizeDouble(entryPrice, _Digits);
         if(newSL > curSL + _Point)
         {
            if(trade.PositionModify(_Symbol, newSL, tp3Level))
               PrintFormat("BE BUY | price=%.2f → SL=entry=%.2f", bid, newSL);
         }
      }
      if(!tp2Hit && bid >= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL > curSL + _Point)
         {
            if(trade.PositionModify(_Symbol, newSL, tp3Level))
               PrintFormat("TP2 BUY | SL→TP1=%.2f (profit locked)", newSL);
         }
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
   else if(posTyp == POSITION_TYPE_SELL)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      if(!beActivated && ask <= beLevel)
      {
         beActivated = true;
         double newSL = NormalizeDouble(entryPrice, _Digits);
         if(newSL < curSL - _Point)
         {
            if(trade.PositionModify(_Symbol, newSL, tp3Level))
               PrintFormat("BE SELL | price=%.2f → SL=entry=%.2f", ask, newSL);
         }
      }
      if(!tp2Hit && ask <= tp2Level)
      {
         tp2Hit = true;
         double newSL = NormalizeDouble(tp1Level, _Digits);
         if(newSL < curSL - _Point)
         {
            if(trade.PositionModify(_Symbol, newSL, tp3Level))
               PrintFormat("TP2 SELL | SL→TP1=%.2f (profit locked)", newSL);
         }
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
}

//+------------------------------------------------------------------+
void DoPartialClose(double pct)
{
   double vMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double vStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double cur   = PositionGetDouble(POSITION_VOLUME);
   double close = MathFloor(cur*pct/100.0/vStep)*vStep;
   if(close >= vMin) trade.PositionClosePartial(_Symbol, close);
}

//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   if(!PositionSelect(_Symbol)) return false;
   return (PositionGetInteger(POSITION_MAGIC) == MagicNumber);
}

//+------------------------------------------------------------------+
void ClosePosition(string reason)
{
   if(!HasOpenPosition()) return;
   double pnl = PositionGetDouble(POSITION_PROFIT);
   if(trade.PositionClose(_Symbol))
      PrintFormat("Closed | reason=%s | pnl=$%.2f", reason, pnl);
}

//+------------------------------------------------------------------+
bool IsTradingDay(int dow)
{
   if(dow==0||dow==6) return false;
   if(dow==1 && !FilterMonday)    return false;
   if(dow==2 && !FilterTuesday)   return false;
   if(dow==3 && !FilterWednesday) return false;
   if(dow==4 && !FilterThursday)  return false;
   if(dow==5 && !FilterFriday)    return false;
   return true;
}

