}
function warning(text) {
  return new Paragraph({
    spacing: { before: 80, after: 80 },
    shading: { fill: "FFF3CD", type: ShadingType.CLEAR },
    border: { left: { style: BorderStyle.SINGLE, size: 12, color: "FFC107", space: 6 } },
    children: [new TextRun({ text: "⚠  " + text, font: "Arial", size: 20, color: "7D4E00", bold: true })]
  });
}
function ok(text) {
  return new Paragraph({
    spacing: { before: 80, after: 80 },
    shading: { fill: TGREEN, type: ShadingType.CLEAR },
    border: { left: { style: BorderStyle.SINGLE, size: 12, color: "27AE60", space: 6 } },
    children: [new TextRun({ text: "✓  " + text, font: "Arial", size: 20, color: GREEN, bold: true })]
  });
}

function makeTable(headers, rows, colWidths) {
  const total = colWidths.reduce((a,b) => a+b, 0);
  return new Table({
    width: { size: total, type: WidthType.DXA },
    columnWidths: colWidths,
    rows: [
      new TableRow({
        tableHeader: true,
        children: headers.map((h, i) => new TableCell({
          borders,
          width: { size: colWidths[i], type: WidthType.DXA },
          shading: { fill: BLUE, type: ShadingType.CLEAR },
