//|    MinSL_Points      = 8200                                     |
//|    MaxSL_Points      = 20000                                    |
//|    ATR_MinMultiplier = 0.3                                      |
//|    MagicNumber       = 202402                                   |
//+------------------------------------------------------------------+
#property copyright "BreakoutNY v4 DJI30 — FundingPips"
#property version   "4.00"
#property description "BreakoutNY — DJI30 — Validated IS PF=1.609 | OOS PF=2.017"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

CTrade        trade;
CPositionInfo posInfo;

//=== INPUTS — SESSION ====================================================
input group   "=== SESSION ==="
input int     ServerOffsetHours  = 2;    // Server UTC offset (UTC+2 FundingPips)
input int     EntryWindowEnd_Min = 15;   // Entry window: 14:50 to 14:50+N UTC
input int     SessionCloseHour   = 17;   // Force-close hour (UTC) — NEVER >23
input int     SessionCloseMin    = 0;    // Force-close minute (UTC)

//=== INPUTS — RISK ========================================================
input group   "=== RISK ==="
input double  RiskAmountUSD      = 50.0; // Risk per trade USD
                                          // $5k challenge → $50 (1%)
                                          // $25k          → $250 (1%)
                                          // $50k          → $500 (1%)
                                          // $100k         → $1000 (1%)

//=== INPUTS — TRADE MANAGEMENT ============================================
input group   "=== TRADE MANAGEMENT ==="
input double  BE_BufferPct       = 50.0; // % of SL before BE activates
input double  TP1_RR             = 1.0;  // TP1 (SL already at entry by here)
input double  TP2_RR             = 2.0;  // TP2: SL moves to TP1
input double  TP3_RR             = 3.0;  // TP3: hard close

//=== INPUTS — PARTIALS ====================================================
input group   "=== PARTIALS (keep false) ==="
input bool    EnablePartials     = false;
input double  TP2_ClosePct       = 40.0; // Only if EnablePartials=true (max 80%)

//=== INPUTS — DAY FILTERS =================================================
input group   "=== DAY FILTERS ==="
input bool    FilterMonday       = true;
input bool    FilterTuesday      = true;
input bool    FilterWednesday    = false; // KEEP FALSE — confirmed 10+ backtests
input bool    FilterThursday     = true;
input bool    FilterFriday       = true;

//=== INPUTS — RANGE FILTER ================================================
input group   "=== RANGE FILTER ==="
input double  MinSL_Points       = 8200.0;  // From optimization sweet spot
input double  MaxSL_Points       = 20000.0; // Stable across optimization
input bool    ConfirmOnClose     = true;     // ALWAYS true

//=== INPUTS — ATR FILTER ==================================================
input group   "=== ATR FILTER (keep enabled) ==="
input bool    ATR_FilterEnable   = true;
input int     ATR_Period         = 14;
input double  ATR_MaxMultiplier  = 2.0;
input double  ATR_MinMultiplier  = 0.3;
input int     ATR_BaselineDays   = 20;

//=== INPUTS — MISC ========================================================
input group   "=== MISC ==="
input bool    EnableCSV          = true;
input string  CSVFileName        = "BreakoutNY_v4_DJI30_trades";
input int     MagicNumber        = 202402; // DJI30=202402, NAS100=202401

//=== GLOBAL STATE =========================================================
double   g_rangeHigh      = 0;
double   g_rangeLow       = 0;
double   g_slDistance     = 0;   // in points
double   g_cachedLots     = 0;
double   g_cachedVPP      = 0;   // ValuePerPoint — computed once at init

bool     g_rangeFormed    = false;
bool     g_tradedToday    = false;
bool     g_brkPending     = false;
int      g_brkDir         = 0;
datetime g_brkBarTime     = 0;

double   g_entryPrice     = 0;
double   g_originalSL     = 0;
double   g_beLevel        = 0;
double   g_tp1Level       = 0;
double   g_tp2Level       = 0;
double   g_tp3Level       = 0;
bool     g_beActivated    = false;
bool     g_tp2Hit         = false;

int      g_atrHandle      = INVALID_HANDLE;
int      g_csvHandle      = INVALID_HANDLE;
datetime g_lastBarTime    = 0;
int      g_lastResetDay   = -1;

//+------------------------------------------------------------------+
//| Get ValuePerPoint — THE KEY FIX                                  |
//| Uses ContractSize*Point (not TickValue/TickSize which = 0 here)  |
//+------------------------------------------------------------------+
double GetValuePerPoint()
{
   double cs  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   double pt  = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double vpp = cs * pt;  // = 5 * 0.01 = $0.05 for DJI30

   if(vpp <= 0)
   {
      Print("ERROR: ContractSize*Point = 0, fallback to OrderCalcProfit");
      double profit = 0;
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      if(OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0,
                         ask, ask + 100.0*pt, profit) && profit > 0)
         return profit / 100.0;
      Print("FATAL: Cannot determine ValuePerPoint");
      return 0;
   }

   // Cross-check with OrderCalcProfit for verification at startup
   double profitCheck = 0;
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   if(ask > 0 && OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0,
                                  ask, ask + 100.0*pt, profitCheck)
      && profitCheck > 0)
   {
      double vppCheck = profitCheck / 100.0;
      double err = MathAbs(vpp - vppCheck) / vppCheck * 100.0;
      PrintFormat("VPP check: Formula=$%.6f  OrderCalcProfit=$%.6f  Error=%.2f%%",
                  vpp, vppCheck, err);
      if(err > 5.0)
      {
         PrintFormat("WARNING: Formula mismatch %.2f%% — using OrderCalcProfit", err);
         return vppCheck;
      }
   }
   return vpp;
}

//+------------------------------------------------------------------+
//| OnInit                                                           |
//+------------------------------------------------------------------+
int OnInit()
{
   // Validation
   if(_Period != PERIOD_M5)
   { Alert("Must run on M5. Current: ", EnumToString(_Period)); return INIT_FAILED; }
   if(BE_BufferPct < 0 || BE_BufferPct >= 100)
   { Alert("BE_BufferPct must be 0-99"); return INIT_FAILED; }
   if(!(TP1_RR > 0 && TP2_RR > TP1_RR && TP3_RR > TP2_RR))
   { Alert("TP ratios must satisfy 0 < TP1 < TP2 < TP3"); return INIT_FAILED; }
   if(SessionCloseHour > 23)
   { Alert("SessionCloseHour must be 0-23. You set: ", SessionCloseHour); return INIT_FAILED; }

   trade.SetExpertMagicNumber(MagicNumber);
   trade.SetDeviationInPoints(20);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   // Compute and cache VPP
   g_cachedVPP = GetValuePerPoint();
   if(g_cachedVPP <= 0)
   { Alert("FATAL: Cannot determine ValuePerPoint — EA cannot size positions"); return INIT_FAILED; }

   // Print startup info
   double cs      = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   double pt      = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double volMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double volStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   Print("============================================================");
   Print("  BreakoutNY v4.0 FINAL — DJI30 FundingPips");
   Print("============================================================");
   PrintFormat("  Symbol        : %s", _Symbol);
   PrintFormat("  ContractSize  : %.1f", cs);
   PrintFormat("  Point         : %.4f", pt);
   PrintFormat("  ValuePerPoint : $%.6f per _Point per lot  ← CRITICAL", g_cachedVPP);
   PrintFormat("  VolumeMin     : %.2f | VolumeStep: %.2f", volMin, volStep);
   PrintFormat("  RiskAmountUSD : $%.2f", RiskAmountUSD);
   PrintFormat("  SessionClose  : %02d:%02d UTC", SessionCloseHour, SessionCloseMin);
   PrintFormat("  BE_Buffer     : %.0f%%  TP: %.1fR/%.1fR/%.1fR",
               BE_BufferPct, TP1_RR, TP2_RR, TP3_RR);
   PrintFormat("  Days active   : Mon=%s Tue=%s Wed=%s Thu=%s Fri=%s",
               FilterMonday?"Y":"N", FilterTuesday?"Y":"N",
               FilterWednesday?"Y":"N", FilterThursday?"Y":"N", FilterFriday?"Y":"N");

   // Lot table
   Print("  --- Lot sizing verification ---");
   double slTest[] = {8200, 10000, 12000, 16000, 20000};
   for(int i = 0; i < ArraySize(slTest); i++)
   {
      double lRaw = RiskAmountUSD / (slTest[i] * g_cachedVPP);
      double lRnd = MathRound(lRaw / volStep) * volStep;
      double lFin = MathMax(MathMin(lRnd, volMax), volMin);
      double risk = lFin * slTest[i] * g_cachedVPP;
      PrintFormat("  SL=%5.0fpts → lots=%.3f → risk=$%.2f (%.3f%%)",
                  slTest[i], lFin, risk, risk/100000.0*100.0);
   }
   Print("============================================================");

   if(StringFind(_Symbol, "DJI30") < 0 && StringFind(_Symbol, "DJ30") < 0 &&
      StringFind(_Symbol, "US30") < 0 && StringFind(_Symbol, "USTEC") < 0)
      PrintFormat("WARNING: Running on %s — expected DJI30 variant", _Symbol);

   // ATR handle
   g_atrHandle = iATR(_Symbol, PERIOD_M5, ATR_Period);
   if(g_atrHandle == INVALID_HANDLE)
   { Print("ERROR: Failed ATR handle"); return INIT_FAILED; }

   // CSV
   if(EnableCSV)
   {
      string path = CSVFileName + ".csv";
      g_csvHandle = FileOpen(path, FILE_READ|FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
      if(g_csvHandle != INVALID_HANDLE)
      {
         FileSeek(g_csvHandle, 0, SEEK_END);
         if(FileTell(g_csvHandle) == 0)
            FileWrite(g_csvHandle,
               "Date","Day","Dir","Lots","VPP","Risk$","Entry",
               "SL","BE","TP1","TP2","TP3","SL_pts","ATR");
         FileFlush(g_csvHandle);
      }
   }
   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if(g_csvHandle != INVALID_HANDLE){ FileFlush(g_csvHandle); FileClose(g_csvHandle); }
   if(g_atrHandle != INVALID_HANDLE) IndicatorRelease(g_atrHandle);
}

//+------------------------------------------------------------------+
void OnTick()
{
   datetime serverNow = TimeCurrent();
   datetime utcNow    = serverNow - ServerOffsetHours * 3600;
   MqlDateTime utcDT;
   TimeToStruct(utcNow, utcDT);

   //--- Daily reset
   if(utcDT.day != g_lastResetDay)
   {
      g_lastResetDay   = utcDT.day;
      g_rangeFormed    = false;
      g_tradedToday    = false;
      g_brkPending     = false;
      g_brkDir         = 0;
      g_rangeHigh = g_rangeLow = g_slDistance = g_cachedLots = 0;
      g_beActivated = g_tp2Hit = false;
      g_entryPrice = g_originalSL = 0;
   }

   //--- Force close at session end
   if(HasOpenPosition())
   {
      bool mustClose = (utcDT.hour > SessionCloseHour) ||
                       (utcDT.hour == SessionCloseHour && utcDT.min >= SessionCloseMin);
      if(mustClose)
      { ClosePosition("SESSION_END"); return; }
      ManagePosition();
      return;
   }

   if(g_tradedToday) return;
   if(!IsTradingDay(utcDT.day_of_week)) return;

   datetime curBar = iTime(_Symbol, PERIOD_M5, 0);
   bool newBar     = (curBar != g_lastBarTime);
   if(newBar) g_lastBarTime = curBar;

   //--- Try to form range at/after 14:50 UTC
   if(!g_rangeFormed)
   {
      int totalMin = utcDT.hour * 60 + utcDT.min;
      if(totalMin >= 14 * 60 + 50)
         TryFormRange(serverNow, utcDT);
   }
   if(!g_rangeFormed) return;

   //--- Check entry window
   int totMin = utcDT.hour * 60 + utcDT.min;
   int wStart = 14 * 60 + 50;
   int wEnd   = wStart + EntryWindowEnd_Min;
   if(totMin < wStart || totMin >= wEnd) return;

   //--- Detect breakout
   if(!g_brkPending)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      if(ask > g_rangeHigh)
      { g_brkPending=true; g_brkDir=1;  g_brkBarTime=curBar;
        PrintFormat("Breakout UP: ask=%.2f > high=%.2f", ask, g_rangeHigh); }
      else if(bid < g_rangeLow)
      { g_brkPending=true; g_brkDir=-1; g_brkBarTime=curBar;
        PrintFormat("Breakout DN: bid=%.2f < low=%.2f", bid, g_rangeLow); }
   }

   //--- Confirm on next bar
   if(g_brkPending && newBar && curBar != g_brkBarTime)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      bool ok = (g_brkDir==1 && ask>g_rangeHigh) ||
                (g_brkDir==-1 && bid<g_rangeLow);
      if(ok) ExecuteTrade(g_brkDir);
      else
      { Print("False breakout — price returned to range, no entry");
        g_brkPending=false; g_brkDir=0; }
   }
}

//+------------------------------------------------------------------+
void TryFormRange(datetime serverNow, MqlDateTime &utcDT)
{
   datetime srvMid = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                               utcDT.year, utcDT.mon, utcDT.day));
   // Convert UTC candle times to server time
   datetime c1 = srvMid + (14 + ServerOffsetHours)*3600 + 35*60;
   datetime c2 = srvMid + (14 + ServerOffsetHours)*3600 + 40*60;
   datetime c3 = srvMid + (14 + ServerOffsetHours)*3600 + 45*60;

   int i1 = iBarShift(_Symbol, PERIOD_M5, c1, false);
   int i2 = iBarShift(_Symbol, PERIOD_M5, c2, false);
   int i3 = iBarShift(_Symbol, PERIOD_M5, c3, false);
   if(i1<0 || i2<0 || i3<0) { Print("Range candles not found yet"); return; }

   // Verify the bars are within 5 minutes of expected times
   if(MathAbs((int)(iTime(_Symbol,PERIOD_M5,i1)-c1)) > 300 ||
      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i2)-c2)) > 300 ||
      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i3)-c3)) > 300)
   { Print("Range candle mismatch — check ServerOffsetHours setting"); return; }

   g_rangeHigh = MathMax(iHigh(_Symbol,PERIOD_M5,i1),
                MathMax(iHigh(_Symbol,PERIOD_M5,i2), iHigh(_Symbol,PERIOD_M5,i3)));
   g_rangeLow  = MathMin(iLow(_Symbol, PERIOD_M5,i1),
                MathMin(iLow(_Symbol, PERIOD_M5,i2), iLow(_Symbol, PERIOD_M5,i3)));
   g_slDistance = (g_rangeHigh - g_rangeLow) / _Point;

   PrintFormat("Range: H=%.2f L=%.2f dist=%.0f pts", g_rangeHigh, g_rangeLow, g_slDistance);

   if(g_slDistance < MinSL_Points)
   { PrintFormat("SKIP: Range %.0f < MinSL %.0f", g_slDistance, MinSL_Points); return; }
   if(g_slDistance > MaxSL_Points)
   { PrintFormat("SKIP: Range %.0f > MaxSL %.0f", g_slDistance, MaxSL_Points); return; }

   if(ATR_FilterEnable && !CheckATRFilter()) return;

   g_cachedLots = CalculateLotSize(g_slDistance);
   if(g_cachedLots <= 0) { Print("SKIP: Lot calculation failed"); return; }

   g_rangeFormed = true;
   PrintFormat("Range valid | lots=%.3f | risk=$%.2f",
               g_cachedLots, g_cachedLots * g_slDistance * g_cachedVPP);
}

//+------------------------------------------------------------------+
bool CheckATRFilter()
{
   double cur[]; ArraySetAsSeries(cur, true);
   if(CopyBuffer(g_atrHandle, 0, 1, 1, cur) <= 0) return true;
   double currentATR = cur[0];

   double base[]; ArraySetAsSeries(base, true);
   int copied = CopyBuffer(g_atrHandle, 0, 1, ATR_BaselineDays*78, base);
   if(copied < 10) return true;

   double sum = 0;
   for(int i=0; i<copied; i++) sum += base[i];
   double baseline = sum / copied;

   PrintFormat("ATR: current=%.4f baseline=%.4f min=%.4f max=%.4f",
               currentATR, baseline, baseline*ATR_MinMultiplier, baseline*ATR_MaxMultiplier);

   if(currentATR < baseline * ATR_MinMultiplier) { Print("ATR too low — skip"); return false; }
   if(currentATR > baseline * ATR_MaxMultiplier) { Print("ATR too high — skip"); return false; }
   return true;
}

//+------------------------------------------------------------------+
//| Lot size calculation — uses g_cachedVPP (ContractSize*Point)    |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPts)
{
   if(g_cachedVPP <= 0) { Print("ERROR: VPP=0 in CalculateLotSize"); return 0; }

   double volMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double volStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   double lotsRaw = RiskAmountUSD / (slPts * g_cachedVPP);
   double lots    = MathRound(lotsRaw / volStep) * volStep;
   lots           = MathMax(MathMin(lots, volMax), volMin);

   double actualRisk = lots * slPts * g_cachedVPP;
   PrintFormat("Lots: raw=%.4f → %.3f | risk=$%.2f", lotsRaw, lots, actualRisk);

   // Margin check
   double marginReq = 0;
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots,
                      SymbolInfoDouble(_Symbol, SYMBOL_ASK), marginReq))
   {
      if(marginReq > AccountInfoDouble(ACCOUNT_MARGIN_FREE) * 0.90)
      { Print("ERROR: Insufficient margin for ", lots, " lots"); return 0; }
   }
   return lots;
}

//+------------------------------------------------------------------+
void ExecuteTrade(int direction)
{
   if(g_cachedLots <= 0) return;

   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slD = g_slDistance * _Point;

   if(direction == 1) // BUY
   {
      g_entryPrice = ask;
      g_originalSL = NormalizeDouble(ask - slD,                       _Digits);
      g_beLevel    = NormalizeDouble(ask + slD * (BE_BufferPct/100.0), _Digits);
      g_tp1Level   = NormalizeDouble(ask + slD * TP1_RR,               _Digits);
      g_tp2Level   = NormalizeDouble(ask + slD * TP2_RR,               _Digits);
      g_tp3Level   = NormalizeDouble(ask + slD * TP3_RR,               _Digits);

      if(trade.Buy(g_cachedLots, _Symbol, ask, g_originalSL, g_tp3Level, "BreakoutNY_BUY"))
      {
         g_tradedToday=true; g_brkPending=false;
         g_beActivated=false; g_tp2Hit=false;
         PrintFormat("BUY | %.3f lots | entry=%.2f SL=%.2f BE@%.2f TP1=%.2f TP2=%.2f TP3=%.2f",
                     g_cachedLots, ask, g_originalSL, g_beLevel,
                     g_tp1Level, g_tp2Level, g_tp3Level);
         LogTrade("BUY");
      }
   }
   else // SELL
   {
      g_entryPrice = bid;
      g_originalSL = NormalizeDouble(bid + slD,                        _Digits);
      g_beLevel    = NormalizeDouble(bid - slD * (BE_BufferPct/100.0), _Digits);
      g_tp1Level   = NormalizeDouble(bid - slD * TP1_RR,               _Digits);
      g_tp2Level   = NormalizeDouble(bid - slD * TP2_RR,               _Digits);
      g_tp3Level   = NormalizeDouble(bid - slD * TP3_RR,               _Digits);

      if(trade.Sell(g_cachedLots, _Symbol, bid, g_originalSL, g_tp3Level, "BreakoutNY_SELL"))
      {
         g_tradedToday=true; g_brkPending=false;
         g_beActivated=false; g_tp2Hit=false;
         PrintFormat("SELL | %.3f lots | entry=%.2f SL=%.2f BE@%.2f TP1=%.2f TP2=%.2f TP3=%.2f",
                     g_cachedLots, bid, g_originalSL, g_beLevel,
                     g_tp1Level, g_tp2Level, g_tp3Level);
         LogTrade("SELL");
      }
   }
}

//+------------------------------------------------------------------+
void ManagePosition()
{
   if(!HasOpenPosition()) return;
   double curSL  = PositionGetDouble(POSITION_SL);
   long   posTyp = PositionGetInteger(POSITION_TYPE);

   if(posTyp == POSITION_TYPE_BUY)
   {
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      // BE activation
      if(!g_beActivated && bid >= g_beLevel)
      {
         g_beActivated = true;
         double newSL = NormalizeDouble(g_entryPrice, _Digits);
         if(newSL > curSL + _Point)
            if(trade.PositionModify(_Symbol, newSL, g_tp3Level))
               PrintFormat("BE BUY | price=%.2f → SL=entry=%.2f", bid, newSL);
      }

      // TP2: lock profit at TP1
      if(!g_tp2Hit && bid >= g_tp2Level)
      {
         g_tp2Hit = true;
         double newSL = NormalizeDouble(g_tp1Level, _Digits);
         if(newSL > curSL + _Point)
            if(trade.PositionModify(_Symbol, newSL, g_tp3Level))
               PrintFormat("TP2 BUY | SL→TP1=%.2f (profit locked)", newSL);
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
   else if(posTyp == POSITION_TYPE_SELL)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

      if(!g_beActivated && ask <= g_beLevel)
      {
         g_beActivated = true;
         double newSL = NormalizeDouble(g_entryPrice, _Digits);
         if(newSL < curSL - _Point)
            if(trade.PositionModify(_Symbol, newSL, g_tp3Level))
               PrintFormat("BE SELL | price=%.2f → SL=entry=%.2f", ask, newSL);
      }

      if(!g_tp2Hit && ask <= g_tp2Level)
      {
         g_tp2Hit = true;
         double newSL = NormalizeDouble(g_tp1Level, _Digits);
         if(newSL < curSL - _Point)
            if(trade.PositionModify(_Symbol, newSL, g_tp3Level))
               PrintFormat("TP2 SELL | SL→TP1=%.2f (profit locked)", newSL);
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
}

//+------------------------------------------------------------------+
void DoPartialClose(double pct)
{
   if(pct <= 0 || pct > 100) return;
   double vMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double vStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double cur   = PositionGetDouble(POSITION_VOLUME);
   double toClose = MathFloor(cur * pct / 100.0 / vStep) * vStep;
   if(toClose >= vMin) trade.PositionClosePartial(_Symbol, toClose);
}

//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   if(!PositionSelect(_Symbol)) return false;
   return ((int)PositionGetInteger(POSITION_MAGIC) == MagicNumber);
}

//+------------------------------------------------------------------+
void ClosePosition(string reason)
{
   if(!HasOpenPosition()) return;
   double pnl = PositionGetDouble(POSITION_PROFIT);
   if(trade.PositionClose(_Symbol))
      PrintFormat("CLOSED | reason=%s | P&L=$%.2f", reason, pnl);
}

//+------------------------------------------------------------------+
bool IsTradingDay(int dow)
{
   if(dow == 0 || dow == 6) return false; // Weekend
   if(dow == 1 && !FilterMonday)    return false;
   if(dow == 2 && !FilterTuesday)   return false;
   if(dow == 3 && !FilterWednesday) return false;
   if(dow == 4 && !FilterThursday)  return false;
   if(dow == 5 && !FilterFriday)    return false;
   return true;
}

//+------------------------------------------------------------------+
void LogTrade(string dir)
{
   if(!EnableCSV || g_csvHandle == INVALID_HANDLE) return;
   datetime utcNow = TimeCurrent() - ServerOffsetHours*3600;
   MqlDateTime dt; TimeToStruct(utcNow, dt);
   string dayNames[] = {"Sun","Mon","Tue","Wed","Thu","Fri","Sat"};
   double atrBuf[]; ArraySetAsSeries(atrBuf, true);
   double atr = 0;
   if(CopyBuffer(g_atrHandle, 0, 1, 1, atrBuf) > 0) atr = atrBuf[0];
   double risk = g_cachedLots * g_slDistance * g_cachedVPP;
   FileWrite(g_csvHandle,
      TimeToString(utcNow, TIME_DATE), dayNames[dt.day_of_week], dir,
      DoubleToString(g_cachedLots, 3),
      DoubleToString(g_cachedVPP, 6),
      DoubleToString(risk, 2),
      DoubleToString(g_entryPrice, _Digits),
      DoubleToString(g_originalSL, _Digits),
      DoubleToString(g_beLevel, _Digits),
      DoubleToString(g_tp1Level, _Digits),
      DoubleToString(g_tp2Level, _Digits),
      DoubleToString(g_tp3Level, _Digits),
      DoubleToString(g_slDistance, 0),
      DoubleToString(atr, 4));
   FileFlush(g_csvHandle);
}
