//+------------------------------------------------------------------+
//| Get ValuePerPoint — THE KEY FIX                                  |
//| Uses ContractSize*Point (not TickValue/TickSize which = 0 here)  |
//+------------------------------------------------------------------+
double GetValuePerPoint()
{
   double cs  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_CONTRACT_SIZE);
   double pt  = SymbolInfoDouble(_Symbol, SYMBOL_POINT);
   double vpp = cs * pt;  // = 5 * 0.01 = $0.05 for DJI30

   if(vpp <= 0)
   {
      Print("ERROR: ContractSize*Point = 0, fallback to OrderCalcProfit");
      double profit = 0;
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      if(OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0,
                         ask, ask + 100.0*pt, profit) && profit > 0)
         return profit / 100.0;
      Print("FATAL: Cannot determine ValuePerPoint");
      return 0;
   }

   // Cross-check with OrderCalcProfit for verification at startup
   double profitCheck = 0;
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   if(ask > 0 && OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0,
                                  ask, ask + 100.0*pt, profitCheck)
      && profitCheck > 0)
   {
      double vppCheck = profitCheck / 100.0;
      double err = MathAbs(vpp - vppCheck) / vppCheck * 100.0;
      PrintFormat("VPP check: Formula=$%.6f  OrderCalcProfit=$%.6f  Error=%.2f%%",
                  vpp, vppCheck, err);
      if(err > 5.0)
      {
         PrintFormat("WARNING: Formula mismatch %.2f%% — using OrderCalcProfit", err);
         return vppCheck;
      }
   }
   return vpp;
}

