//+------------------------------------------------------------------+
void OnTick()
{
   datetime serverNow = TimeCurrent();
   datetime utcNow    = serverNow - ServerOffsetHours * 3600;
   MqlDateTime utcDT;
   TimeToStruct(utcNow, utcDT);

   //--- Daily reset
   if(utcDT.day != g_lastResetDay)
   {
      g_lastResetDay   = utcDT.day;
      g_rangeFormed    = false;
      g_tradedToday    = false;
      g_brkPending     = false;
      g_brkDir         = 0;
      g_rangeHigh = g_rangeLow = g_slDistance = g_cachedLots = 0;
      g_beActivated = g_tp2Hit = false;
      g_entryPrice = g_originalSL = 0;
   }

   //--- Force close at session end
   if(HasOpenPosition())
   {
      bool mustClose = (utcDT.hour > SessionCloseHour) ||
                       (utcDT.hour == SessionCloseHour && utcDT.min >= SessionCloseMin);
      if(mustClose)
      { ClosePosition("SESSION_END"); return; }
      ManagePosition();
      return;
   }

   if(g_tradedToday) return;
   if(!IsTradingDay(utcDT.day_of_week)) return;

   datetime curBar = iTime(_Symbol, PERIOD_M5, 0);
   bool newBar     = (curBar != g_lastBarTime);
   if(newBar) g_lastBarTime = curBar;

   //--- Try to form range at/after 14:50 UTC
   if(!g_rangeFormed)
   {
      int totalMin = utcDT.hour * 60 + utcDT.min;
      if(totalMin >= 14 * 60 + 50)
         TryFormRange(serverNow, utcDT);
   }
   if(!g_rangeFormed) return;

   //--- Check entry window
   int totMin = utcDT.hour * 60 + utcDT.min;
   int wStart = 14 * 60 + 50;
   int wEnd   = wStart + EntryWindowEnd_Min;
   if(totMin < wStart || totMin >= wEnd) return;

   //--- Detect breakout
   if(!g_brkPending)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      if(ask > g_rangeHigh)
      { g_brkPending=true; g_brkDir=1;  g_brkBarTime=curBar;
        PrintFormat("Breakout UP: ask=%.2f > high=%.2f", ask, g_rangeHigh); }
      else if(bid < g_rangeLow)
      { g_brkPending=true; g_brkDir=-1; g_brkBarTime=curBar;
        PrintFormat("Breakout DN: bid=%.2f < low=%.2f", bid, g_rangeLow); }
   }

   //--- Confirm on next bar
   if(g_brkPending && newBar && curBar != g_brkBarTime)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      bool ok = (g_brkDir==1 && ask>g_rangeHigh) ||
                (g_brkDir==-1 && bid<g_rangeLow);
      if(ok) ExecuteTrade(g_brkDir);
      else
      { Print("False breakout — price returned to range, no entry");
        g_brkPending=false; g_brkDir=0; }
   }
}

//+------------------------------------------------------------------+
void TryFormRange(datetime serverNow, MqlDateTime &utcDT)
{
   datetime srvMid = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                               utcDT.year, utcDT.mon, utcDT.day));
   // Convert UTC candle times to server time
   datetime c1 = srvMid + (14 + ServerOffsetHours)*3600 + 35*60;
   datetime c2 = srvMid + (14 + ServerOffsetHours)*3600 + 40*60;
   datetime c3 = srvMid + (14 + ServerOffsetHours)*3600 + 45*60;

   int i1 = iBarShift(_Symbol, PERIOD_M5, c1, false);
   int i2 = iBarShift(_Symbol, PERIOD_M5, c2, false);
   int i3 = iBarShift(_Symbol, PERIOD_M5, c3, false);
   if(i1<0 || i2<0 || i3<0) { Print("Range candles not found yet"); return; }

   // Verify the bars are within 5 minutes of expected times
   if(MathAbs((int)(iTime(_Symbol,PERIOD_M5,i1)-c1)) > 300 ||
      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i2)-c2)) > 300 ||
      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i3)-c3)) > 300)
   { Print("Range candle mismatch — check ServerOffsetHours setting"); return; }

   g_rangeHigh = MathMax(iHigh(_Symbol,PERIOD_M5,i1),
                MathMax(iHigh(_Symbol,PERIOD_M5,i2), iHigh(_Symbol,PERIOD_M5,i3)));
   g_rangeLow  = MathMin(iLow(_Symbol, PERIOD_M5,i1),
                MathMin(iLow(_Symbol, PERIOD_M5,i2), iLow(_Symbol, PERIOD_M5,i3)));
   g_slDistance = (g_rangeHigh - g_rangeLow) / _Point;

   PrintFormat("Range: H=%.2f L=%.2f dist=%.0f pts", g_rangeHigh, g_rangeLow, g_slDistance);

   if(g_slDistance < MinSL_Points)
   { PrintFormat("SKIP: Range %.0f < MinSL %.0f", g_slDistance, MinSL_Points); return; }
   if(g_slDistance > MaxSL_Points)
   { PrintFormat("SKIP: Range %.0f > MaxSL %.0f", g_slDistance, MaxSL_Points); return; }

   if(ATR_FilterEnable && !CheckATRFilter()) return;

   g_cachedLots = CalculateLotSize(g_slDistance);
   if(g_cachedLots <= 0) { Print("SKIP: Lot calculation failed"); return; }

   g_rangeFormed = true;
   PrintFormat("Range valid | lots=%.3f | risk=$%.2f",
               g_cachedLots, g_cachedLots * g_slDistance * g_cachedVPP);
}

//+------------------------------------------------------------------+
bool CheckATRFilter()
{
   double cur[]; ArraySetAsSeries(cur, true);
   if(CopyBuffer(g_atrHandle, 0, 1, 1, cur) <= 0) return true;
   double currentATR = cur[0];

   double base[]; ArraySetAsSeries(base, true);
   int copied = CopyBuffer(g_atrHandle, 0, 1, ATR_BaselineDays*78, base);
   if(copied < 10) return true;

   double sum = 0;
   for(int i=0; i<copied; i++) sum += base[i];
   double baseline = sum / copied;

   PrintFormat("ATR: current=%.4f baseline=%.4f min=%.4f max=%.4f",
               currentATR, baseline, baseline*ATR_MinMultiplier, baseline*ATR_MaxMultiplier);

   if(currentATR < baseline * ATR_MinMultiplier) { Print("ATR too low — skip"); return false; }
   if(currentATR > baseline * ATR_MaxMultiplier) { Print("ATR too high — skip"); return false; }
   return true;
}

//+------------------------------------------------------------------+
//| Lot size calculation — uses g_cachedVPP (ContractSize*Point)    |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPts)
{
   if(g_cachedVPP <= 0) { Print("ERROR: VPP=0 in CalculateLotSize"); return 0; }

   double volMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double volMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double volStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   double lotsRaw = RiskAmountUSD / (slPts * g_cachedVPP);
   double lots    = MathRound(lotsRaw / volStep) * volStep;
   lots           = MathMax(MathMin(lots, volMax), volMin);

   double actualRisk = lots * slPts * g_cachedVPP;
   PrintFormat("Lots: raw=%.4f → %.3f | risk=$%.2f", lotsRaw, lots, actualRisk);

   // Margin check
   double marginReq = 0;
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots,
                      SymbolInfoDouble(_Symbol, SYMBOL_ASK), marginReq))
   {
      if(marginReq > AccountInfoDouble(ACCOUNT_MARGIN_FREE) * 0.90)
      { Print("ERROR: Insufficient margin for ", lots, " lots"); return 0; }
   }
   return lots;
}

//+------------------------------------------------------------------+
void ExecuteTrade(int direction)
{
   if(g_cachedLots <= 0) return;

   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double slD = g_slDistance * _Point;

   if(direction == 1) // BUY
   {
      g_entryPrice = ask;
      g_originalSL = NormalizeDouble(ask - slD,                       _Digits);
      g_beLevel    = NormalizeDouble(ask + slD * (BE_BufferPct/100.0), _Digits);
      g_tp1Level   = NormalizeDouble(ask + slD * TP1_RR,               _Digits);
      g_tp2Level   = NormalizeDouble(ask + slD * TP2_RR,               _Digits);
      g_tp3Level   = NormalizeDouble(ask + slD * TP3_RR,               _Digits);

      if(trade.Buy(g_cachedLots, _Symbol, ask, g_originalSL, g_tp3Level, "BreakoutNY_BUY"))
      {
         g_tradedToday=true; g_brkPending=false;
         g_beActivated=false; g_tp2Hit=false;
         PrintFormat("BUY | %.3f lots | entry=%.2f SL=%.2f BE@%.2f TP1=%.2f TP2=%.2f TP3=%.2f",
                     g_cachedLots, ask, g_originalSL, g_beLevel,
                     g_tp1Level, g_tp2Level, g_tp3Level);
         LogTrade("BUY");
      }
   }
   else // SELL
   {
      g_entryPrice = bid;
      g_originalSL = NormalizeDouble(bid + slD,                        _Digits);
      g_beLevel    = NormalizeDouble(bid - slD * (BE_BufferPct/100.0), _Digits);
      g_tp1Level   = NormalizeDouble(bid - slD * TP1_RR,               _Digits);
      g_tp2Level   = NormalizeDouble(bid - slD * TP2_RR,               _Digits);
      g_tp3Level   = NormalizeDouble(bid - slD * TP3_RR,               _Digits);

      if(trade.Sell(g_cachedLots, _Symbol, bid, g_originalSL, g_tp3Level, "BreakoutNY_SELL"))
      {
         g_tradedToday=true; g_brkPending=false;
         g_beActivated=false; g_tp2Hit=false;
         PrintFormat("SELL | %.3f lots | entry=%.2f SL=%.2f BE@%.2f TP1=%.2f TP2=%.2f TP3=%.2f",
                     g_cachedLots, bid, g_originalSL, g_beLevel,
                     g_tp1Level, g_tp2Level, g_tp3Level);
         LogTrade("SELL");
      }
   }
}

//+------------------------------------------------------------------+
void ManagePosition()
{
   if(!HasOpenPosition()) return;
   double curSL  = PositionGetDouble(POSITION_SL);
   long   posTyp = PositionGetInteger(POSITION_TYPE);

   if(posTyp == POSITION_TYPE_BUY)
   {
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);

      // BE activation
      if(!g_beActivated && bid >= g_beLevel)
      {
         g_beActivated = true;
         double newSL = NormalizeDouble(g_entryPrice, _Digits);
         if(newSL > curSL + _Point)
            if(trade.PositionModify(_Symbol, newSL, g_tp3Level))
               PrintFormat("BE BUY | price=%.2f → SL=entry=%.2f", bid, newSL);
      }

      // TP2: lock profit at TP1
      if(!g_tp2Hit && bid >= g_tp2Level)
      {
         g_tp2Hit = true;
         double newSL = NormalizeDouble(g_tp1Level, _Digits);
         if(newSL > curSL + _Point)
            if(trade.PositionModify(_Symbol, newSL, g_tp3Level))
               PrintFormat("TP2 BUY | SL→TP1=%.2f (profit locked)", newSL);
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
   else if(posTyp == POSITION_TYPE_SELL)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

      if(!g_beActivated && ask <= g_beLevel)
      {
         g_beActivated = true;
         double newSL = NormalizeDouble(g_entryPrice, _Digits);
         if(newSL < curSL - _Point)
            if(trade.PositionModify(_Symbol, newSL, g_tp3Level))
               PrintFormat("BE SELL | price=%.2f → SL=entry=%.2f", ask, newSL);
      }

      if(!g_tp2Hit && ask <= g_tp2Level)
      {
         g_tp2Hit = true;
         double newSL = NormalizeDouble(g_tp1Level, _Digits);
         if(newSL < curSL - _Point)
            if(trade.PositionModify(_Symbol, newSL, g_tp3Level))
               PrintFormat("TP2 SELL | SL→TP1=%.2f (profit locked)", newSL);
         if(EnablePartials) DoPartialClose(TP2_ClosePct);
      }
   }
}

//+------------------------------------------------------------------+
void DoPartialClose(double pct)
{
   if(pct <= 0 || pct > 100) return;
   double vMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double vStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   double cur   = PositionGetDouble(POSITION_VOLUME);
   double toClose = MathFloor(cur * pct / 100.0 / vStep) * vStep;
   if(toClose >= vMin) trade.PositionClosePartial(_Symbol, toClose);
}

//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   if(!PositionSelect(_Symbol)) return false;
   return ((int)PositionGetInteger(POSITION_MAGIC) == MagicNumber);
}

//+------------------------------------------------------------------+
void ClosePosition(string reason)
{
   if(!HasOpenPosition()) return;
   double pnl = PositionGetDouble(POSITION_PROFIT);
   if(trade.PositionClose(_Symbol))
      PrintFormat("CLOSED | reason=%s | P&L=$%.2f", reason, pnl);
}

//+------------------------------------------------------------------+
bool IsTradingDay(int dow)
{
   if(dow == 0 || dow == 6) return false; // Weekend
   if(dow == 1 && !FilterMonday)    return false;
   if(dow == 2 && !FilterTuesday)   return false;
   if(dow == 3 && !FilterWednesday) return false;
   if(dow == 4 && !FilterThursday)  return false;
   if(dow == 5 && !FilterFriday)    return false;
   return true;
}

