//|  CRITICAL FIX — ValuePerPoint:                                  |
//|    OLD (v1-v3): TickValue/TickSize = 0/0 → always 0.01 lots    |
//|    NEW (v4):    ContractSize*Point = 5*0.01 = $0.05/point/lot  |
//|    Verified by OrderCalcProfit: $5.00 per 100pts per 1 lot     |
//|                                                                  |
//|  FOR $5k CHALLENGE: set RiskAmountUSD = 50 (1% of $5,000)      |
//|  Scale: $25k→$250  $50k→$500  $100k→$1000                     |
//+------------------------------------------------------------------+
#property copyright "BreakoutNY v4 DJI30 FundingPips"
#property version   "4.00"
#property description "IS PF=1.609 | OOS PF=2.017 | MaxDD<4%"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

CTrade        trade;
CPositionInfo posInfo;

input group   "=== SESSION ==="
input int     ServerOffsetHours  = 2;
input int     EntryWindowEnd_Min = 15;
input int     SessionCloseHour   = 17;   // CRITICAL — never set >23
input int     SessionCloseMin    = 0;

input group   "=== RISK ==="
input double  RiskAmountUSD      = 50.0; // $5k challenge=50, $100k=1000

input group   "=== TRADE MANAGEMENT ==="
input double  BE_BufferPct       = 50.0;
input double  TP1_RR             = 1.0;
input double  TP2_RR             = 2.0;
input double  TP3_RR             = 3.0;

input group   "=== PARTIALS ==="
input bool    EnablePartials     = false;
input double  TP2_ClosePct       = 40.0;

input group   "=== DAY FILTERS ==="
input bool    FilterMonday       = true;
input bool    FilterTuesday      = true;
input bool    FilterWednesday    = false; // KEEP FALSE — confirmed
input bool    FilterThursday     = true;
input bool    FilterFriday       = true;

input group   "=== RANGE FILTER ==="
input double  MinSL_Points       = 8200.0;
input double  MaxSL_Points       = 20000.0;
input bool    ConfirmOnClose     = true;

input group   "=== ATR FILTER ==="
input bool    ATR_FilterEnable   = true;
input int     ATR_Period         = 14;
input double  ATR_MaxMultiplier  = 2.0;
input double  ATR_MinMultiplier  = 0.3;
