#define CLR_RANGE_H  clrLightSteelBlue
#define CLR_RANGE_L  clrLightSteelBlue

//--- Line names
string L_SL    = OBJ_PREFIX+"SL";
string L_BE    = OBJ_PREFIX+"BE";
string L_ENTRY = OBJ_PREFIX+"ENTRY";
string L_TP1   = OBJ_PREFIX+"TP1";
string L_TP2   = OBJ_PREFIX+"TP2";
string L_TP3   = OBJ_PREFIX+"TP3";
string L_RH    = OBJ_PREFIX+"RANGE_H";
string L_RL    = OBJ_PREFIX+"RANGE_L";

//+------------------------------------------------------------------+
void DrawHLine(string name, double price, color clr, string label,
               int style=STYLE_SOLID, int width=1)
{
   if(ObjectFind(0, name) < 0)
      ObjectCreate(0, name, OBJ_HLINE, 0, 0, price);
   ObjectSetDouble(0, name, OBJPROP_PRICE,     price);
   ObjectSetInteger(0, name, OBJPROP_COLOR,    clr);
   ObjectSetInteger(0, name, OBJPROP_STYLE,    style);
   ObjectSetInteger(0, name, OBJPROP_WIDTH,    width);
   ObjectSetString(0, name, OBJPROP_TEXT,      label);
   ObjectSetInteger(0, name, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, name, OBJPROP_HIDDEN,   false);
   ObjectSetInteger(0, name, OBJPROP_BACK,     false);
   ChartRedraw(0);
}

//+------------------------------------------------------------------+
void DeleteLine(string name)
{
   if(ObjectFind(0, name) >= 0)
      ObjectDelete(0, name);
}

//+------------------------------------------------------------------+
void DrawAllLevels()
{
   if(g_entryPrice <= 0) return;

   // Entry
   DrawHLine(L_ENTRY, g_entryPrice, CLR_ENTRY,
             StringFormat("Entry  %.2f", g_entryPrice),
             STYLE_DASH, 1);

   // SL — red solid thick
   DrawHLine(L_SL, g_originalSL, CLR_SL,
             StringFormat("SL  %.2f  (-1R)", g_originalSL),
             STYLE_SOLID, 2);

   // BE — orange dashed
   DrawHLine(L_BE, g_beLevel, CLR_BE,
             StringFormat("BE  %.2f  (%.0f%%)", g_beLevel, BE_BufferPct),
             STYLE_DOT, 1);

   // TP1 — cyan
   DrawHLine(L_TP1, g_tp1Level, CLR_TP1,
             StringFormat("TP1  %.2f  (+%.1fR)", g_tp1Level, TP1_RR),
             STYLE_DOT, 1);

   // TP2 — lime green
   DrawHLine(L_TP2, g_tp2Level, CLR_TP2,
             StringFormat("TP2  %.2f  (+%.1fR)", g_tp2Level, TP2_RR),
             STYLE_DASH, 1);

   // TP3 — chartreuse solid thick
   DrawHLine(L_TP3, g_tp3Level, CLR_TP3,
             StringFormat("TP3  %.2f  (+%.1fR)", g_tp3Level, TP3_RR),
             STYLE_SOLID, 2);
}

//+------------------------------------------------------------------+
void DrawRangeLines()
{
   if(g_rangeHigh <= 0) return;

   DrawHLine(L_RH, g_rangeHigh, CLR_RANGE_H,
             StringFormat("Range High  %.2f", g_rangeHigh),
             STYLE_DOT, 1);
   DrawHLine(L_RL, g_rangeLow, CLR_RANGE_L,
             StringFormat("Range Low  %.2f", g_rangeLow),
             STYLE_DOT, 1);
}

//+------------------------------------------------------------------+
void DeleteAllLevels()
{
   DeleteLine(L_SL);
   DeleteLine(L_BE);
   DeleteLine(L_ENTRY);
   DeleteLine(L_TP1);
   DeleteLine(L_TP2);
   DeleteLine(L_TP3);
}

void DeleteRangeLines()
{
   DeleteLine(L_RH);
   DeleteLine(L_RL);
}

void DeleteAllVisuals()
{
   DeleteAllLevels();
   DeleteRangeLines();
   ChartRedraw(0);
}

