      if(ptexts[i] == "") { ObjectDelete(0, VIS_PFX+pnames[i]); continue; }
      string nm = VIS_PFX + pnames[i];
      if(ObjectFind(0, nm) < 0)
         ObjectCreate(0, nm, OBJ_LABEL, 0, 0, 0);
