// Helpers de objetos
void VisHLine(const string name, double price, color clr,
              ENUM_LINE_STYLE style, int width, const string label)
{
   if(ObjectFind(0,name)<0) ObjectCreate(0,name,OBJ_HLINE,0,0,price);
   ObjectSetDouble(0,  name, OBJPROP_PRICE,      price);
   ObjectSetInteger(0, name, OBJPROP_COLOR,      clr);
   ObjectSetInteger(0, name, OBJPROP_STYLE,      style);
   ObjectSetInteger(0, name, OBJPROP_WIDTH,      width);
   ObjectSetString(0,  name, OBJPROP_TEXT,       label);
   ObjectSetInteger(0, name, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, name, OBJPROP_HIDDEN,     false);
   ObjectSetInteger(0, name, OBJPROP_BACK,       false);
}

void VisText(const string name, datetime t, double price,
             const string txt, color clr, int fontSize,
             ENUM_ANCHOR_POINT anchor, bool background)
{
   if(ObjectFind(0,name)<0) ObjectCreate(0,name,OBJ_TEXT,0,t,price);
   ObjectSetInteger(0, name, OBJPROP_TIME,       t, 0);
   ObjectSetDouble(0,  name, OBJPROP_PRICE,      price);
   ObjectSetString(0,  name, OBJPROP_TEXT,       txt);
   ObjectSetInteger(0, name, OBJPROP_COLOR,      clr);
   ObjectSetInteger(0, name, OBJPROP_FONTSIZE,   fontSize);
   ObjectSetString(0,  name, OBJPROP_FONT,       "Consolas");
   ObjectSetInteger(0, name, OBJPROP_ANCHOR,     anchor);
   ObjectSetInteger(0, name, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, name, OBJPROP_HIDDEN,     false);
   ObjectSetInteger(0, name, OBJPROP_BACK,       background);
}

// Nivel horizontal con label al lado DERECHO
void VisLevel(const string name,
              double price, color clr, ENUM_LINE_STYLE style, int width,
              const string label)
{
   VisHLine(name, price, clr, style, width, label);
   // Label: precio en texto, anclado a la derecha del chart con offset fijo
   string   priceStr = DoubleToString(price, _Digits<=5 ? 1 : _Digits);
   string   lblName  = name + "_LBL";
   datetime tNow     = TimeCurrent();
   VisText(lblName, tNow, price,
           " " + label + " " + priceStr,
           clr, 7, ANCHOR_LEFT_UPPER, false);
}

// Actualiza precio de una línea ya dibujada (SL dinámico)
void VisMoveSLLine(double newPrice)
{
   string name    = VIS_PFX+"SL";
   string lblName = name + "_LBL";
   if(ObjectFind(0,name)<0) return;
   ObjectSetDouble(0, name, OBJPROP_PRICE, newPrice, 0);
   ObjectSetDouble(0, name, OBJPROP_PRICE, newPrice, 1);
   if(ObjectFind(0,lblName)<0) return;
   ObjectSetDouble(0, lblName, OBJPROP_PRICE, newPrice);
   string priceStr = DoubleToString(newPrice, _Digits<=5 ? 1 : _Digits);
   ObjectSetString(0, lblName, OBJPROP_TEXT, " SL " + priceStr);
   ChartRedraw(0);
}

// Banda de rango 14:35–14:45 UTC (rectángulo de fondo)
void VisDrawRangeBand(MqlDateTime &utcDT)
{
   if(!VIS_Enable) return;
   datetime srvMid = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                               utcDT.year, utcDT.mon, utcDT.day));
   datetime t35 = srvMid + (14+ServerOffsetHours)*3600 + 35*60;
   datetime t45 = srvMid + (14+ServerOffsetHours)*3600 + 50*60; // hasta 14:50

   // Rectángulo de fondo de la zona del rango
   string nRect = VIS_PFX+"RZONE";
   if(ObjectFind(0,nRect)<0)
      ObjectCreate(0,nRect,OBJ_RECTANGLE,0,t35,g_rangeHigh,t45,g_rangeLow);
   ObjectSetInteger(0,nRect,OBJPROP_TIME,  t35, 0);
   ObjectSetDouble(0, nRect,OBJPROP_PRICE, g_rangeHigh, 0);
   ObjectSetInteger(0,nRect,OBJPROP_TIME,  t45, 1);
   ObjectSetDouble(0, nRect,OBJPROP_PRICE, g_rangeLow, 1);
   ObjectSetInteger(0,nRect,OBJPROP_COLOR, VIS_ColRange);
   ObjectSetInteger(0,nRect,OBJPROP_STYLE, STYLE_SOLID);
   ObjectSetInteger(0,nRect,OBJPROP_WIDTH, 1);
   ObjectSetInteger(0,nRect,OBJPROP_BACK,  true);
   ObjectSetInteger(0,nRect,OBJPROP_SELECTABLE,false);
   ObjectSetInteger(0,nRect,OBJPROP_HIDDEN,true);

   // Borde superior del rango (Range High)
   string nRH = VIS_PFX+"RH";
   if(ObjectFind(0,nRH)<0) ObjectCreate(0,nRH,OBJ_TREND,0,t35,g_rangeHigh,t45,g_rangeHigh);
   ObjectSetInteger(0,nRH,OBJPROP_TIME,  t35,0);
   ObjectSetDouble(0, nRH,OBJPROP_PRICE, g_rangeHigh,0);
   ObjectSetInteger(0,nRH,OBJPROP_TIME,  t45,1);
   ObjectSetDouble(0, nRH,OBJPROP_PRICE, g_rangeHigh,1);
   ObjectSetInteger(0,nRH,OBJPROP_COLOR, VIS_ColRangeBorder);
   ObjectSetInteger(0,nRH,OBJPROP_WIDTH, 2);
   ObjectSetInteger(0,nRH,OBJPROP_STYLE, STYLE_SOLID);
   ObjectSetInteger(0,nRH,OBJPROP_RAY_RIGHT,false);
   ObjectSetInteger(0,nRH,OBJPROP_SELECTABLE,false);
   ObjectSetInteger(0,nRH,OBJPROP_HIDDEN,true);

   // Borde inferior del rango (Range Low)
   string nRL = VIS_PFX+"RL";
   if(ObjectFind(0,nRL)<0) ObjectCreate(0,nRL,OBJ_TREND,0,t35,g_rangeLow,t45,g_rangeLow);
   ObjectSetInteger(0,nRL,OBJPROP_TIME,  t35,0);
   ObjectSetDouble(0, nRL,OBJPROP_PRICE, g_rangeLow,0);
   ObjectSetInteger(0,nRL,OBJPROP_TIME,  t45,1);
   ObjectSetDouble(0, nRL,OBJPROP_PRICE, g_rangeLow,1);
   ObjectSetInteger(0,nRL,OBJPROP_COLOR, VIS_ColRangeBorder);
   ObjectSetInteger(0,nRL,OBJPROP_WIDTH, 2);
   ObjectSetInteger(0,nRL,OBJPROP_STYLE, STYLE_SOLID);
   ObjectSetInteger(0,nRL,OBJPROP_RAY_RIGHT,false);
   ObjectSetInteger(0,nRL,OBJPROP_SELECTABLE,false);
   ObjectSetInteger(0,nRL,OBJPROP_HIDDEN,true);

   ChartRedraw(0);
}

// Dibuja todos los niveles de precio tras entrar al trade
void VisDrawLevels()
{
   if(!VIS_Enable || g_entryPrice<=0) return;

   // Entry
   VisLevel(VIS_PFX+"ENTRY", g_entryPrice,
            VIS_ColEntry, STYLE_DASH, 1, "Entry");

   // SL — rojo sólido grueso
   VisLevel(VIS_PFX+"SL", g_originalSL,
            VIS_ColSL, STYLE_SOLID, 2, "SL");

   // BE — cian punteado (solo si VIS_ShowBE)
   if(VIS_ShowBE)
      VisLevel(VIS_PFX+"BE", g_beLevel,
               VIS_ColBE, STYLE_DOT, 1, StringFormat("BE (%.0f%%)", BE_BufferPct));

   // TP1 — amarillo punteado
   VisLevel(VIS_PFX+"TP1", g_tp1Level,
            VIS_ColTP1, STYLE_DOT, 1, "TP1 +1R");

   // TP2 — naranja punteado
   VisLevel(VIS_PFX+"TP2", g_tp2Level,
            VIS_ColTP2, STYLE_DASH, 1, "TP2 +2R");

   // TP3 — verde sólido grueso (target final)
   VisLevel(VIS_PFX+"TP3", g_tp3Level,
            VIS_ColTP3, STYLE_SOLID, 2, "TP3 +3R");

   // Marcador de cierre de sesión (línea vertical 17:00 UTC)
   datetime serverNow = TimeCurrent();
   MqlDateTime utcDT; TimeToStruct(serverNow - ServerOffsetHours*3600, utcDT);
   datetime srvMid = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                               utcDT.year, utcDT.mon, utcDT.day));
   datetime tClose = srvMid + (SessionCloseHour+ServerOffsetHours)*3600 + SessionCloseMin*60;
   string nSC = VIS_PFX+"SC";
   if(ObjectFind(0,nSC)<0) ObjectCreate(0,nSC,OBJ_VLINE,0,tClose,0);
   ObjectSetInteger(0,nSC,OBJPROP_COLOR,      C'100,100,140');
   ObjectSetInteger(0,nSC,OBJPROP_STYLE,      STYLE_DASH);
   ObjectSetInteger(0,nSC,OBJPROP_WIDTH,      1);
   ObjectSetInteger(0,nSC,OBJPROP_BACK,       true);
   ObjectSetInteger(0,nSC,OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0,nSC,OBJPROP_HIDDEN,     true);
   VisText(VIS_PFX+"SCL", tClose, g_tp3Level,
           StringFormat(" %d:%02d UTC", SessionCloseHour, SessionCloseMin),
           C'100,100,160', 7, ANCHOR_LEFT_UPPER, false);

   // Flecha → antes del rango indicando dirección de ruptura
   bool isBuy = (g_tradeDir == "buy");
   double arrPx = isBuy ? g_rangeHigh : g_rangeLow;
   datetime tArr = tClose - (datetime)(2*PeriodSeconds(PERIOD_M5)*100); // aprox 2h antes del cierre
   // Usamos el tiempo actual menos 5 velas como referencia del rango
   datetime tArrActual = iTime(_Symbol,PERIOD_M5,10); // ~50 min atrás
   string nArr = VIS_PFX+"ARR";
   if(ObjectFind(0,nArr)<0) ObjectCreate(0,nArr,OBJ_ARROW,0,tArrActual,arrPx);
   ObjectSetDouble(0,  nArr, OBJPROP_PRICE,      arrPx);
   ObjectSetInteger(0, nArr, OBJPROP_TIME,       tArrActual, 0);
   ObjectSetInteger(0, nArr, OBJPROP_ARROWCODE,  232);   // → flecha derecha horizontal
   ObjectSetInteger(0, nArr, OBJPROP_COLOR,      isBuy ? VIS_ColTP3 : VIS_ColSL);
   ObjectSetInteger(0, nArr, OBJPROP_WIDTH,      3);
   ObjectSetInteger(0, nArr, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, nArr, OBJPROP_HIDDEN,     true);

   ChartRedraw(0);
   // Actualizar panel con dirección y SL
   VisUpdatePanel(g_tradeDir, g_slDistance, 0, true, false, "");
}

// Elimina TODOS los objetos visuales del EA
void VisDeleteAll()
{
   string names[] = {
      "ENTRY","ENTRY_LBL","SL","SL_LBL","BE","BE_LBL",
      "TP1","TP1_LBL","TP2","TP2_LBL","TP3","TP3_LBL",
      "RZONE","RH","RL","SC","SCL","ARR",
      "PNL1","PNL2","PNL3","PNL4","PNL5",
      "MOTTO1","MOTTO2","MOTTO3"
   };
   for(int i=0; i<ArraySize(names); i++) {
      string n = VIS_PFX+names[i];
      if(ObjectFind(0,n)>=0) ObjectDelete(0,n);
   }
   ChartRedraw(0);
}

//===================================================================
//  PANEL FIJO — esquina superior derecha con P/L en tiempo real
//===================================================================
void VisUpdatePanel(string direction, double slPts, double netPL,
                    bool hasTrade, bool isFiltered, string filterReason)
{
   if(!VIS_Enable || !VIS_ShowLabel) return;

   MqlDateTime u; TimeToStruct(TimeCurrent()-ServerOffsetHours*3600, u);
   string days[] = {"Dom","Lun","Mar","Mié","Jue","Vie","Sáb"};
   string dayStr  = days[u.day_of_week];
   string dateStr = StringFormat("%02d/%02d/%04d", u.day, u.mon, u.year);

   string line1, line2, line3, line4;
   color  panelColor;

   if(isFiltered) {
      line1 = "BreakoutNY v4.1  |  " + _Symbol;
      line2 = dayStr + " " + dateStr;
      line3 = "★  " + filterReason;
      line4 = "Riesgo: $" + DoubleToString(RiskAmountUSD,0) + "/trade";
      panelColor = C'100,100,140';
   } else if(!hasTrade && direction=="") {
      line1 = "BreakoutNY v4.1  |  " + _Symbol;
      line2 = dayStr + " " + dateStr + "  |  Esperando 14:50 UTC";
      line3 = "Riesgo $" + DoubleToString(RiskAmountUSD,0) +
              "  |  SL " + DoubleToString(MinSL_Points,0) +
              "–" + DoubleToString(MaxSL_Points,0) + " pts";
      line4 = "TP1 1:" + DoubleToString(TP1_RR,0) +
              "  TP2 1:" + DoubleToString(TP2_RR,0) +
              "  TP3 1:" + DoubleToString(TP3_RR,0);
      panelColor = C'100,130,180';
   } else {
      bool isBuy   = (direction=="buy");
      string arrow = isBuy ? "▲ BUY" : "▼ SELL";
      string plStr = (netPL>=0)
         ? "+ $" + DoubleToString(netPL,0)
         : "- $" + DoubleToString(MathAbs(netPL),0);
      line1 = "BreakoutNY v4.1  |  " + _Symbol + "  |  " + dayStr;
      line2 = arrow + "  |  SL " + DoubleToString(slPts,1) + " pts" +
              "  |  TP3 " + DoubleToString(slPts*TP3_RR,1) + " pts";
      line3 = "Riesgo $" + DoubleToString(RiskAmountUSD,0) +
              "  |  BE " + DoubleToString(BE_BufferPct,0) + "%";
      line4 = hasTrade ? ("P/L flotante:  " + plStr) : "Sin posición abierta";
      panelColor = isBuy ? VIS_ColTP3 : VIS_ColSL;
   }

   string pnames[] = {"PNL1","PNL2","PNL3","PNL4"};
   string ptexts[] = {line1, line2, line3, line4};
   int    pyoffs[] = {15, 30, 45, 60};
   int    pfonts[] = {9, 9, 8, 9};

   for(int i=0; i<4; i++) {
      string nm = VIS_PFX+pnames[i];
      if(ObjectFind(0,nm)<0) ObjectCreate(0,nm,OBJ_LABEL,0,0,0);
      ObjectSetInteger(0,nm,OBJPROP_CORNER,    CORNER_RIGHT_UPPER);
      ObjectSetInteger(0,nm,OBJPROP_XDISTANCE, 12);
      ObjectSetInteger(0,nm,OBJPROP_YDISTANCE, pyoffs[i]);
      ObjectSetString(0, nm,OBJPROP_TEXT,      ptexts[i]);
      ObjectSetInteger(0,nm,OBJPROP_COLOR,     (i==0) ? C'195,208,230' : panelColor);
      ObjectSetInteger(0,nm,OBJPROP_FONTSIZE,  pfonts[i]);
      ObjectSetString(0, nm,OBJPROP_FONT,      "Consolas");
      ObjectSetInteger(0,nm,OBJPROP_ANCHOR,    ANCHOR_RIGHT_UPPER);
      ObjectSetInteger(0,nm,OBJPROP_SELECTABLE,false);
      ObjectSetInteger(0,nm,OBJPROP_HIDDEN,    false);
      ObjectSetInteger(0,nm,OBJPROP_BACK,      false);
   }
   ChartRedraw(0);
}

