// Dibuja un segmento OBJ_TREND acotado en tiempo (no cruza todo el gráfico)
// Usar para niveles históricos y para el trade actual
void VisSegment(const string name,
                datetime t1, datetime t2, double p1, double p2,
                color clr, ENUM_LINE_STYLE style, int width, bool rayRight)
{
   if(ObjectFind(0,name)<0) ObjectCreate(0,name,OBJ_TREND,0,t1,p1,t2,p2);
   ObjectSetInteger(0,name,OBJPROP_TIME,     t1,0);
   ObjectSetDouble(0, name,OBJPROP_PRICE,    p1,0);
   ObjectSetInteger(0,name,OBJPROP_TIME,     t2,1);
   ObjectSetDouble(0, name,OBJPROP_PRICE,    p2,1);
   ObjectSetInteger(0,name,OBJPROP_COLOR,    clr);
   ObjectSetInteger(0,name,OBJPROP_STYLE,    style);
   ObjectSetInteger(0,name,OBJPROP_WIDTH,    width);
   ObjectSetInteger(0,name,OBJPROP_RAY_RIGHT,rayRight);
   ObjectSetInteger(0,name,OBJPROP_SELECTABLE,false);
   ObjectSetInteger(0,name,OBJPROP_HIDDEN,   false);
   ObjectSetInteger(0,name,OBJPROP_BACK,     false);
}

