//+------------------------------------------------------------------+
// VisDrawHistoricalDay — dibuja SL/BE/TP de UN día pasado
// Lee el historial de deals de MT5 para ese día
// tag = identificador único del día, e.g. "20250115"
//+------------------------------------------------------------------+
void VisDrawHistoricalDay(datetime dayServerStart, const string tag)
{
   // Ventana del día: desde medianoche hasta medianoche siguiente
   datetime dayEnd = dayServerStart + 86400;

   // Seleccionar deals del historial para ese día
   if(!HistorySelect(dayServerStart, dayEnd)) return;
   int totalDeals = HistoryDealsTotal();
   if(totalDeals < 2) return; // necesitamos al menos entrada y salida

   // Buscar el deal de entrada (IN) de nuestro MagicNumber
   ulong ticketIn = 0;
   datetime tEntryDeal = 0;
   double   priceEntry = 0;
   string   dealComment = "";

   for(int i=0; i<totalDeals; i++)
   {
      ulong ticket = HistoryDealGetTicket(i);
      if(ticket==0) continue;
      if((int)HistoryDealGetInteger(ticket,DEAL_MAGIC) != MagicNumber) continue;
      if(HistoryDealGetString(ticket,DEAL_SYMBOL) != _Symbol) continue;
      ENUM_DEAL_ENTRY entry = (ENUM_DEAL_ENTRY)HistoryDealGetInteger(ticket,DEAL_ENTRY);
      if(entry != DEAL_ENTRY_IN) continue;

      ticketIn     = ticket;
      tEntryDeal   = (datetime)HistoryDealGetInteger(ticket,DEAL_TIME);
      priceEntry   = HistoryDealGetDouble(ticket,DEAL_PRICE);
      dealComment  = HistoryDealGetString(ticket,DEAL_COMMENT);
      break;
   }
   if(ticketIn==0 || priceEntry<=0) return;

   // Determinar dirección
   ENUM_DEAL_TYPE dealType = (ENUM_DEAL_TYPE)HistoryDealGetInteger(ticketIn,DEAL_TYPE);
   bool isBuy = (dealType == DEAL_TYPE_BUY);

   // Buscar el deal de salida (OUT) para calcular el tiempo de cierre real
   datetime tCloseDeal = 0;
   double   priceClose = 0;
   string   exitComment = "";
   for(int i=0; i<totalDeals; i++)
   {
      ulong ticket = HistoryDealGetTicket(i);
      if(ticket==0) continue;
      if((int)HistoryDealGetInteger(ticket,DEAL_MAGIC) != MagicNumber) continue;
      if(HistoryDealGetString(ticket,DEAL_SYMBOL) != _Symbol) continue;
      ENUM_DEAL_ENTRY entry = (ENUM_DEAL_ENTRY)HistoryDealGetInteger(ticket,DEAL_ENTRY);
      if(entry != DEAL_ENTRY_OUT) continue;
      tCloseDeal  = (datetime)HistoryDealGetInteger(ticket,DEAL_TIME);
      priceClose  = HistoryDealGetDouble(ticket,DEAL_PRICE);
      exitComment = HistoryDealGetString(ticket,DEAL_COMMENT);
      break;
   }

   // Si no hay salida registrada todavía (trade abierto), usar cierre de sesión
   datetime srvMid   = dayServerStart;
   datetime tClose17 = srvMid + (SessionCloseHour+ServerOffsetHours)*3600 + SessionCloseMin*60;
   datetime tEnd     = (tCloseDeal > 0) ? tCloseDeal : tClose17;

   // Reconstruir los niveles a partir del precio de entrada y la posición
   // Necesitamos el SL original — lo buscamos en el historial de órdenes
   double slPrice  = 0;
   double tp3Price = 0;
   if(HistorySelectByPosition(0)) { // fallback si no encontramos la orden
      // buscar en órdenes del historial
   }

   // Buscar orden de entrada para obtener SL y TP originales
   if(!HistorySelect(dayServerStart, dayEnd)) return;
   int totalOrders = HistoryOrdersTotal();
   for(int i=0; i<totalOrders; i++)
   {
      ulong oTicket = HistoryOrderGetTicket(i);
      if(oTicket==0) continue;
      if((int)HistoryOrderGetInteger(oTicket,ORDER_MAGIC) != MagicNumber) continue;
      if(HistoryOrderGetString(oTicket,ORDER_SYMBOL) != _Symbol) continue;
      ENUM_ORDER_STATE oState = (ENUM_ORDER_STATE)HistoryOrderGetInteger(oTicket,ORDER_STATE);
      if(oState != ORDER_STATE_FILLED) continue;
      slPrice  = HistoryOrderGetDouble(oTicket,ORDER_SL);
      tp3Price = HistoryOrderGetDouble(oTicket,ORDER_TP);
      break;
   }

   // Si no encontramos la orden, no podemos reconstruir los niveles
   if(slPrice<=0 || tp3Price<=0) return;

   // Calcular distancia del SL en puntos
   double slDist = MathAbs(priceEntry - slPrice);
   double slPts  = slDist / _Point;
   if(slPts < 100) return; // dato inválido

   // Reconstruir todos los niveles
   double tp1 = isBuy ? priceEntry+slDist*TP1_RR : priceEntry-slDist*TP1_RR;
   double tp2 = isBuy ? priceEntry+slDist*TP2_RR : priceEntry-slDist*TP2_RR;
   double tp3 = tp3Price; // el TP real que se puso en la orden
   double beLv = isBuy ? priceEntry+slDist*(BE_BufferPct/100.0)
                       : priceEntry-slDist*(BE_BufferPct/100.0);

   // Dibujar todos los segmentos acotados (tEntryDeal → tEnd)
   VisSegmentLabeled(VIS_PFX+"H_ENTRY_"+tag, tEntryDeal, tEnd,
                     priceEntry, VIS_ColEntry, STYLE_DASH, 1, "E");
   VisSegmentLabeled(VIS_PFX+"H_SL_"+tag, tEntryDeal, tEnd,
                     slPrice, VIS_ColSL, STYLE_SOLID, 2, "SL");
   if(VIS_ShowBE)
      VisSegmentLabeled(VIS_PFX+"H_BE_"+tag, tEntryDeal, tEnd,
                        beLv, VIS_ColBE, STYLE_DOT, 1, "BE");
   VisSegmentLabeled(VIS_PFX+"H_TP1_"+tag, tEntryDeal, tEnd,
                     tp1, VIS_ColTP1, STYLE_DOT, 1, "TP1");
   VisSegmentLabeled(VIS_PFX+"H_TP2_"+tag, tEntryDeal, tEnd,
                     tp2, VIS_ColTP2, STYLE_DASH, 1, "TP2");
   VisSegmentLabeled(VIS_PFX+"H_TP3_"+tag, tEntryDeal, tEnd,
                     tp3, VIS_ColTP3, STYLE_SOLID, 2, "TP3");

   // Marcador de resultado: precio de cierre real
   if(tCloseDeal > 0 && priceClose > 0)
   {
      bool wasWin    = isBuy ? (priceClose > priceEntry) : (priceClose < priceEntry);
      color colClose = wasWin ? VIS_ColTP3 : VIS_ColSL;
      string closeLabel = wasWin ? "✓" : "✗";
      // Punto de cierre (flecha)
      string nExit = VIS_PFX+"H_EXIT_"+tag;
      if(ObjectFind(0,nExit)<0) ObjectCreate(0,nExit,OBJ_ARROW,0,tCloseDeal,priceClose);
      ObjectSetDouble(0,  nExit,OBJPROP_PRICE,     priceClose);
      ObjectSetInteger(0, nExit,OBJPROP_TIME,      tCloseDeal,0);
      ObjectSetInteger(0, nExit,OBJPROP_ARROWCODE, wasWin ? 233 : 234); // ✓ o ✗
      ObjectSetInteger(0, nExit,OBJPROP_COLOR,     colClose);
      ObjectSetInteger(0, nExit,OBJPROP_WIDTH,     2);
      ObjectSetInteger(0, nExit,OBJPROP_SELECTABLE,false);
      ObjectSetInteger(0, nExit,OBJPROP_HIDDEN,    false);
   }

   // Línea vertical de cierre de sesión del día
   string nSCH = VIS_PFX+"H_SC_"+tag;
   if(ObjectFind(0,nSCH)<0) ObjectCreate(0,nSCH,OBJ_VLINE,0,tClose17,0);
   ObjectSetInteger(0,nSCH,OBJPROP_COLOR,     C'70,70,110');
   ObjectSetInteger(0,nSCH,OBJPROP_STYLE,     STYLE_DASH);
   ObjectSetInteger(0,nSCH,OBJPROP_WIDTH,     1);
   ObjectSetInteger(0,nSCH,OBJPROP_BACK,      true);
   ObjectSetInteger(0,nSCH,OBJPROP_SELECTABLE,false);
   ObjectSetInteger(0,nSCH,OBJPROP_HIDDEN,    true);
}

//+------------------------------------------------------------------+
// VisRedrawHistory — redibuja los últimos VIS_LookbackDays días
// Se llama en OnInit() una sola vez
//+------------------------------------------------------------------+
void VisRedrawHistory()
{
   if(!VIS_Enable) return;

   datetime now = TimeCurrent();

   for(int d=VIS_LookbackDays; d>=1; d--)
   {
      // Inicio del día en hora servidor (medianoche)
      datetime daySrv = now - (datetime)(d*86400);
      MqlDateTime dt; TimeToStruct(daySrv, dt);
      // Normalizar a medianoche del día
      datetime dayStart = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                                    dt.year, dt.mon, dt.day));
      // Tag único para este día — evita colisiones entre objetos de distintos días
      string tag = StringFormat("%04d%02d%02d", dt.year, dt.mon, dt.day);

      // Dibujar banda de rango y niveles del trade si hubo uno ese día
      VisDrawHistoricalDay(dayStart, tag);
   }
   ChartRedraw(0);
}

// Elimina TODOS los objetos visuales del EA (actuales e históricos)
void VisDeleteAll()
{
   // Borrar objetos del día actual
   string names[] = {
      "ENTRY","ENTRY_LBL","SL","SL_LBL","BE","BE_LBL",
      "TP1","TP1_LBL","TP2","TP2_LBL","TP3","TP3_LBL",
      "RZONE","RH","RL","SC","SCL","ARR",
      "PNL1","PNL2","PNL3","PNL4",
      "MOTTO1","MOTTO2","MOTTO3"
   };
   for(int i=0; i<ArraySize(names); i++) {
      string n = VIS_PFX+names[i];
      if(ObjectFind(0,n)>=0) ObjectDelete(0,n);
   }
   // Borrar todos los objetos históricos (prefijo BNY_H_)
   // Recorrer todos los objetos del chart y eliminar los que empiecen con nuestro prefijo histórico
   string histPfx = VIS_PFX+"H_";
   int total = ObjectsTotal(0);
   for(int i=total-1; i>=0; i--) {  // recorrer en reversa para no saltar índices
      string objName = ObjectName(0,i);
      if(StringFind(objName, histPfx) == 0)
         ObjectDelete(0, objName);
   }
   ChartRedraw(0);
}

