void VisDrawHistoricalDay(datetime dayServerStart, const string tag)
{
   datetime dayEnd   = dayServerStart + 86400;
   datetime tClose17 = dayServerStart +
                       (SessionCloseHour + ServerOffsetHours)*3600 +
                       SessionCloseMin*60;

   // ─── PASO 1: seleccionar historial del día y buscar deal de entrada ───
   if(!HistorySelect(dayServerStart, dayEnd)) return;

   ulong    ticketIn   = 0;
   datetime tEntryDeal = 0;
   double   priceEntry = 0;
   bool     isBuy      = false;

   int totalDeals = HistoryDealsTotal();
   for(int i=0; i<totalDeals; i++)
   {
      ulong ticket = HistoryDealGetTicket(i);
      if(ticket == 0) continue;
      if((int)HistoryDealGetInteger(ticket, DEAL_MAGIC)  != MagicNumber) continue;
      if(HistoryDealGetString(ticket, DEAL_SYMBOL)       != _Symbol)     continue;
      if((ENUM_DEAL_ENTRY)HistoryDealGetInteger(ticket, DEAL_ENTRY) != DEAL_ENTRY_IN) continue;

      ticketIn   = ticket;
      tEntryDeal = (datetime)HistoryDealGetInteger(ticket, DEAL_TIME);
      priceEntry = HistoryDealGetDouble(ticket, DEAL_PRICE);
      isBuy      = ((ENUM_DEAL_TYPE)HistoryDealGetInteger(ticket, DEAL_TYPE) == DEAL_TYPE_BUY);
      break;
   }
   // Sin trade ese día → nada que dibujar
   if(ticketIn == 0 || priceEntry <= 0) return;

   // ─── PASO 2: buscar deal de salida ────────────────────────────────────
   datetime tCloseDeal = 0;
   double   priceClose = 0;
   for(int i=0; i<totalDeals; i++)
   {
      ulong ticket = HistoryDealGetTicket(i);
      if(ticket == 0) continue;
      if((int)HistoryDealGetInteger(ticket, DEAL_MAGIC) != MagicNumber) continue;
      if(HistoryDealGetString(ticket, DEAL_SYMBOL)      != _Symbol)     continue;
      if((ENUM_DEAL_ENTRY)HistoryDealGetInteger(ticket, DEAL_ENTRY) != DEAL_ENTRY_OUT) continue;
      tCloseDeal = (datetime)HistoryDealGetInteger(ticket, DEAL_TIME);
      priceClose = HistoryDealGetDouble(ticket, DEAL_PRICE);
      break;
   }
   // Fin del segmento: cierre real o 17:00 UTC si no hay salida aún
   datetime tEnd = (tCloseDeal > 0) ? tCloseDeal : tClose17;

   // ─── PASO 3: recuperar SL y TP3 de la orden histórica ─────────────────
   // HistorySelect ya está activo para el mismo período — no repetirlo
   double slPrice  = 0;
   double tp3Price = 0;
   int totalOrders = HistoryOrdersTotal();
   for(int i=0; i<totalOrders; i++)
   {
      ulong oTicket = HistoryOrderGetTicket(i);
      if(oTicket == 0) continue;
      if((int)HistoryOrderGetInteger(oTicket, ORDER_MAGIC) != MagicNumber) continue;
      if(HistoryOrderGetString(oTicket, ORDER_SYMBOL)      != _Symbol)     continue;
      if((ENUM_ORDER_STATE)HistoryOrderGetInteger(oTicket, ORDER_STATE) != ORDER_STATE_FILLED) continue;
      slPrice  = HistoryOrderGetDouble(oTicket, ORDER_SL);
      tp3Price = HistoryOrderGetDouble(oTicket, ORDER_TP);
      break;
   }

   // ─── PASO 4: FALLBACK si ORDER_SL=0 (FundingPips prop firm) ──────────
   // Algunos brokers y prop firms no almacenan el SL en la orden histórica.
   // En ese caso reconstruimos el rango desde el deal de salida o desde
   // los percentiles calibrados. Usamos MinSL_Points como aproximación.
   double slDist = 0;
   if(slPrice <= 0)
   {
      // Intentar leer desde el deal de entrada: algunos brokers guardan
      // el SL en el campo DEAL_SL (no estándar pero existe en algunos)
      double dealSL = HistoryDealGetDouble(ticketIn, DEAL_SL);
      if(dealSL > 0) { slPrice = dealSL; }
      else
      {
         // Último recurso: usar el SL promedio calibrado (MinSL+MaxSL)/2
         // Esto es una aproximación — se verá en el gráfico pero los
         // niveles exactos pueden no coincidir al punto
         double midSL = (MinSL_Points + MaxSL_Points) / 2.0 * _Point;
         slPrice  = isBuy ? priceEntry - midSL : priceEntry + midSL;
         tp3Price = isBuy ? priceEntry + midSL * TP3_RR
                          : priceEntry - midSL * TP3_RR;
      }
   }

   slDist = MathAbs(priceEntry - slPrice);
   double slPts = slDist / _Point;

   // Si el SL calculado es irreal (< 500 pts para DJI30), descartar
   if(slPts < 500 || slDist <= 0) return;

   // Si tp3Price todavía es 0, calcularlo
   if(tp3Price <= 0)
      tp3Price = isBuy ? priceEntry + slDist*TP3_RR
                       : priceEntry - slDist*TP3_RR;

   // ─── PASO 5: reconstruir todos los niveles ─────────────────────────────
   double tp1  = isBuy ? priceEntry + slDist*TP1_RR : priceEntry - slDist*TP1_RR;
   double tp2  = isBuy ? priceEntry + slDist*TP2_RR : priceEntry - slDist*TP2_RR;
   double beLv = isBuy ? priceEntry + slDist*(BE_BufferPct/100.0)
                       : priceEntry - slDist*(BE_BufferPct/100.0);

   // ─── PASO 6: dibujar segmentos acotados (tEntryDeal → tEnd) ──────────
   VisSegmentLabeled(VIS_PFX+"H_ENTRY_"+tag, tEntryDeal, tEnd,
                     priceEntry, VIS_ColEntry, STYLE_DASH, 1, "E");
   VisSegmentLabeled(VIS_PFX+"H_SL_"+tag,    tEntryDeal, tEnd,
                     slPrice,    VIS_ColSL,    STYLE_SOLID, 2, "SL");
   if(VIS_ShowBE)
      VisSegmentLabeled(VIS_PFX+"H_BE_"+tag, tEntryDeal, tEnd,
                        beLv, VIS_ColBE, STYLE_DOT, 1, "BE");
   VisSegmentLabeled(VIS_PFX+"H_TP1_"+tag,   tEntryDeal, tEnd,
                     tp1,  VIS_ColTP1, STYLE_DOT,  1, "TP1");
   VisSegmentLabeled(VIS_PFX+"H_TP2_"+tag,   tEntryDeal, tEnd,
                     tp2,  VIS_ColTP2, STYLE_DASH, 1, "TP2");
   VisSegmentLabeled(VIS_PFX+"H_TP3_"+tag,   tEntryDeal, tEnd,
                     tp3Price, VIS_ColTP3, STYLE_SOLID, 2, "TP3");

   // ─── PASO 7: flecha de resultado al precio de cierre ──────────────────
   if(tCloseDeal > 0 && priceClose > 0)
   {
      bool  wasWin  = isBuy ? (priceClose > priceEntry) : (priceClose < priceEntry);
      color colExit = wasWin ? VIS_ColTP3 : VIS_ColSL;
      // Código 233=checkmark, 234=X (Wingdings MT5)
      string nExit  = VIS_PFX+"H_EXIT_"+tag;
      if(ObjectFind(0,nExit)<0) ObjectCreate(0,nExit,OBJ_ARROW,0,tCloseDeal,priceClose);
      ObjectSetDouble(0,  nExit, OBJPROP_PRICE,      priceClose);
      ObjectSetInteger(0, nExit, OBJPROP_TIME,       tCloseDeal, 0);
      ObjectSetInteger(0, nExit, OBJPROP_ARROWCODE,  wasWin ? 233 : 234);
      ObjectSetInteger(0, nExit, OBJPROP_COLOR,      colExit);
      ObjectSetInteger(0, nExit, OBJPROP_WIDTH,      2);
      ObjectSetInteger(0, nExit, OBJPROP_SELECTABLE, false);
      ObjectSetInteger(0, nExit, OBJPROP_HIDDEN,     false);
   }

   // ─── PASO 8: línea vertical 17:00 UTC de este día ─────────────────────
   string nSCH = VIS_PFX+"H_SC_"+tag;
   if(ObjectFind(0,nSCH)<0) ObjectCreate(0,nSCH,OBJ_VLINE,0,tClose17,0);
   ObjectSetInteger(0,nSCH, OBJPROP_COLOR,      C'70,70,110');
   ObjectSetInteger(0,nSCH, OBJPROP_STYLE,      STYLE_DASH);
   ObjectSetInteger(0,nSCH, OBJPROP_WIDTH,      1);
   ObjectSetInteger(0,nSCH, OBJPROP_BACK,       true);
   ObjectSetInteger(0,nSCH, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0,nSCH, OBJPROP_HIDDEN,     true);
}

void VisRedrawHistory()
{
   if(!VIS_Enable) return;
   datetime now = TimeCurrent();
   PrintFormat("VIS: Iniciando redibujado histórico — últimos %d días", VIS_LookbackDays);

   int daysDrawn = 0;
   for(int d=VIS_LookbackDays; d>=1; d--)
   {
      datetime daySrv  = now - (datetime)(d*86400);
      MqlDateTime dt;  TimeToStruct(daySrv, dt);
      datetime dayStart = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                                    dt.year, dt.mon, dt.day));
      string tag = StringFormat("%04d%02d%02d", dt.year, dt.mon, dt.day);

      // Diagnóstico: ¿cuántos deals hay ese día?
      if(HistorySelect(dayStart, dayStart+86400))
      {
         int nd = HistoryDealsTotal();
         if(nd > 0)
            PrintFormat("VIS: %s — %d deals en historial", tag, nd);
      }

      VisDrawHistoricalDay(dayStart, tag);
      // Contar si se dibujó algo (el objeto de SL existe)
      if(ObjectFind(0, VIS_PFX+"H_SL_"+tag) >= 0) daysDrawn++;
   }
   PrintFormat("VIS: Redibujado completo — %d días con trades visibles", daysDrawn);
   ChartRedraw(0);
}

