void VisRedrawHistory()
{
   if(!VIS_Enable) return;

   datetime now = TimeCurrent();

   for(int d=VIS_LookbackDays; d>=1; d--)
   {
      // Inicio del día en hora servidor (medianoche)
      datetime daySrv = now - (datetime)(d*86400);
      MqlDateTime dt; TimeToStruct(daySrv, dt);
      // Normalizar a medianoche del día
      datetime dayStart = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                                    dt.year, dt.mon, dt.day));
      // Tag único para este día — evita colisiones entre objetos de distintos días
      string tag = StringFormat("%04d%02d%02d", dt.year, dt.mon, dt.day);

      // Dibujar banda de rango y niveles del trade si hubo uno ese día
      VisDrawHistoricalDay(dayStart, tag);
   }
   ChartRedraw(0);
}

