   int    sep      = StringFind(currTxt, " ");
   string lbl      = sep >= 0 ? StringSubstr(currTxt, 0, sep + 1) : currTxt;
   string priceStr = DoubleToString(newPrice, _Digits <= 5 ? 1 : _Digits);
   ObjectSetString(0, lblName, OBJPROP_TEXT, lbl + priceStr + " ");
