   325	void TryFormRange(MqlDateTime &utcDT)
   326	{
   327	   datetime srvMid = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
   328	                                               utcDT.year, utcDT.mon, utcDT.day));
   329	   datetime c1 = srvMid + (14+ServerOffsetHours)*3600 + 35*60;
   330	   datetime c2 = srvMid + (14+ServerOffsetHours)*3600 + 40*60;
   331	   datetime c3 = srvMid + (14+ServerOffsetHours)*3600 + 45*60;
   332	
   333	   int i1=iBarShift(_Symbol,PERIOD_M5,c1,false);
   334	   int i2=iBarShift(_Symbol,PERIOD_M5,c2,false);
   335	   int i3=iBarShift(_Symbol,PERIOD_M5,c3,false);
   336	   if(i1<0||i2<0||i3<0) return; // velas aún no disponibles — reintentar
   337	
   338	   // Marcar como intentado — todos los exits siguientes imprimen 1 sola vez
   339	   g_rangeAttempted = true;
   340	
   341	   if(MathAbs((int)(iTime(_Symbol,PERIOD_M5,i1)-c1))>300 ||
   342	      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i2)-c2))>300 ||
   343	      MathAbs((int)(iTime(_Symbol,PERIOD_M5,i3)-c3))>300)
   344	   { Print("RANGE SKIP: Desfase de velas — verificar ServerOffsetHours"); return; }
   345	
   346	   g_rangeHigh  = MathMax(iHigh(_Symbol,PERIOD_M5,i1),MathMax(iHigh(_Symbol,PERIOD_M5,i2),iHigh(_Symbol,PERIOD_M5,i3)));
   347	   g_rangeLow   = MathMin(iLow(_Symbol, PERIOD_M5,i1),MathMin(iLow(_Symbol, PERIOD_M5,i2),iLow(_Symbol, PERIOD_M5,i3)));
   348	   g_slDistance = (g_rangeHigh - g_rangeLow) / _Point;
   349	
   350	   if(g_slDistance < MinSL_Points) {
   351	      PrintFormat("RANGE SKIP: dist=%.0fpts < MinSL=%.0fpts (rango muy estrecho)", g_slDistance, MinSL_Points);
   352	      if(VIS_Enable) VisUpdatePanel("",0,0,false,true,
   353	         StringFormat("Rango filtrado (%.0fpts < %.0f)", g_slDistance, MinSL_Points));
   354	      return;
   355	   }
   356	   if(g_slDistance > MaxSL_Points) {
   357	      PrintFormat("RANGE SKIP: dist=%.0fpts > MaxSL=%.0fpts (rango muy amplio)", g_slDistance, MaxSL_Points);
   358	      if(VIS_Enable) VisUpdatePanel("",0,0,false,true,
   359	         StringFormat("Rango filtrado (%.0fpts > %.0f)", g_slDistance, MaxSL_Points));
   360	      return;
   361	   }
   362	   if(ATR_FilterEnable && !CheckATRFilter()) return;
   363	
