   375	bool CheckATRFilter()
   376	{
   377	   double cur[]; ArraySetAsSeries(cur, true);
   378	   if(CopyBuffer(g_atrHandle,0,1,1,cur) <= 0) return true;
   379	   double base[]; ArraySetAsSeries(base, true);
   380	   int copied = CopyBuffer(g_atrHandle,0,1,ATR_BaselineDays*78,base);
   381	   if(copied < 10) return true;
   382	   double sum=0; for(int i=0;i<copied;i++) sum+=base[i];
   383	   double baseline = sum/copied;
   384	   if(cur[0] < baseline*ATR_MinMultiplier) {
   385	      PrintFormat("RANGE SKIP: ATR bajo (%.4f < %.4f baseline × %.1f)", cur[0], baseline, ATR_MinMultiplier);
   386	      if(VIS_Enable) VisUpdatePanel("",0,0,false,true,"ATR filtrado (bajo)");
   387	      return false;
   388	   }
   389	   if(cur[0] > baseline*ATR_MaxMultiplier) {
   390	      PrintFormat("RANGE SKIP: ATR alto (%.4f > %.4f baseline × %.1f)", cur[0], baseline, ATR_MaxMultiplier);
   391	      if(VIS_Enable) VisUpdatePanel("",0,0,false,true,"ATR filtrado (alto)");
   392	      return false;
   393	   }
   394	   return true;
   395	}
