   398	void ExecuteTrade(int dir)
   399	{
   400	   if(g_cachedLots <= 0) return;
   401	   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   402	   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   403	   double slD = g_slDistance * _Point;
   404	
   405	   if(dir == 1) {
   406	      g_entryPrice = ask;
   407	      g_originalSL = NormalizeDouble(ask - slD,                      _Digits);
   408	      g_beLevel    = NormalizeDouble(ask + slD*(BE_BufferPct/100.0), _Digits);
   409	      g_tp1Level   = NormalizeDouble(ask + slD*TP1_RR,               _Digits);
   410	      g_tp2Level   = NormalizeDouble(ask + slD*TP2_RR,               _Digits);
   411	      g_tp3Level   = NormalizeDouble(ask + slD*TP3_RR,               _Digits);
   412	      if(trade.Buy(g_cachedLots,_Symbol,ask,g_originalSL,g_tp3Level,"BreakoutNY_BUY")) {
   413	         g_tradedToday=true; g_brkPending=false; g_beActivated=false; g_tp2Hit=false;
   414	         g_tradeDir = "buy";
   415	         PrintFormat("BUY %.3f | SL=%.2f BE=%.2f TP1=%.2f TP2=%.2f TP3=%.2f",
   416	                     g_cachedLots,g_originalSL,g_beLevel,g_tp1Level,g_tp2Level,g_tp3Level);
   417	         vis_hasTrade = true; VisRedrawToday();
   418	         LogTrade("BUY");
   419	      }
   420	   } else {
   421	      g_entryPrice = bid;
   422	      g_originalSL = NormalizeDouble(bid + slD,                      _Digits);
   423	      g_beLevel    = NormalizeDouble(bid - slD*(BE_BufferPct/100.0), _Digits);
